### 4. Data Types - Complete Type Hierarchy

**File:** `/Users/marcus/conductor/workspaces/brain-v1/lahore-v1/app/src/server/tool-registry/types.ts`

#### Tool Types:
```typescript
export type ToolRiskLevel = "low" | "medium" | "high" | "critical";
export type ToolStatus = "active" | "disabled";

// Summary shape for Tools list (Tools tab)
export type ToolListItem = {
  id: string;
  name: string;
  toolkit: string;
  description: string;
  risk_level: ToolRiskLevel;
  status: ToolStatus;
  grant_count: number;
  governance_count: number;
  created_at: string;
};

// Full tool detail with schemas and relationships
export type ToolDetail = ToolListItem & {
  input_schema: Record<string, unknown>;
  output_schema?: Record<string, unknown>;  // ← MCP Draft Spec (RFC 8785)
  grants: GrantDetail[];
  governance_policies: GovernancePolicyDetail[];
};

// SurrealDB record for mcp_tool table
export type McpToolRecord = {
  id: RecordId<"mcp_tool", string>;
  name: string;
  toolkit: string;
  description: string;
  input_schema: Record<string, unknown>;
  output_schema?: Record<string, unknown>;  // ← MCP Draft Spec
  risk_level: ToolRiskLevel;
  status: ToolStatus;
  workspace: RecordId<"workspace", string>;
  provider?: RecordId<"credential_provider", string>;
  source_server?: RecordId<"mcp_server", string>;  // ← Links to parent MCP server
  created_at: Date;
};

// Discovery: Tool as found on remote MCP server
export type ToolSyncDetail = {
  name: string;
  description: string;
  input_schema: Record<string, unknown>;
  output_schema?: Record<string, unknown>;  // ← MCP Draft Spec
  action: ToolSyncAction;  // "create" | "update" | "disable" | "unchanged"
  risk_level: ToolRiskLevel;
};

// Resolved tool from proxy context
export type ResolvedTool = {
  name: string;
  description: string;
  input_schema: Record<string, unknown>;
  output_schema?: Record<string, unknown>;  // ← MCP Draft Spec
  toolkit: string;
  risk_level: string;
  source_server_id?: string;  // ← Optional parent server reference
};
```

#### MCP Server Types:
```typescript
export type McpTransport = "sse" | "streamable-http";
export type McpServerStatus = "ok" | "error" | "auth_error";
export type McpServerAuthMode = "none" | "static_headers" | "oauth" | "provider";

export type McpServerRecord = {
  id: RecordId<"mcp_server", string>;
  name: string;
  url: string;
  transport: McpTransport;
  workspace: RecordId<"workspace", string>;
  auth_mode: McpServerAuthMode;
