388→/**
389→ * Fetch tool detail with grants and governance policies in a single batched query.
390→ *
391→ * Returns undefined if the tool does not exist or does not belong to the workspace.
392→ */
393→export async function getToolDetail(
394→  surreal: Surreal,
395→  toolRecord: RecordId<"mcp_tool", string>,
396→  workspaceRecord: RecordId<"workspace", string>,
397→): Promise<
398→  | {
399→      tool: ToolDetailRow;
400→      grants: GrantDetailRow[];
401→      governancePolicies: GovernancePolicyDetailRow[];
402→    }
403→  | undefined
404→> {
405→  const results = await surreal.query<
406→    [ToolDetailRow[], GrantDetailRow[], GovernancePolicyDetailRow[]]
407→  >(
408→    `SELECT * FROM $tool WHERE workspace = $ws;
409→     SELECT in.id AS identity_id, in.name AS identity_name, max_calls_per_hour, granted_at FROM can_use WHERE out = $tool;
410→     SELECT in.title AS policy_title, in.status AS policy_status, conditions, max_per_call, max_per_day FROM governs_tool WHERE out = $tool;`,
411→    { tool: toolRecord, ws: workspaceRecord },
412→  );
413→
414→  const toolRows = results[0] ?? [];
415→  if (toolRows.length === 0) {
416→    return undefined;
417→  }
418→
419→  return {
420→    tool: toolRows[0],
421→    grants: results[1] ?? [],
422→    governancePolicies: results[2] ?? [],
423→  };
424→}
