458→
459→/**
460→ * Check if an mcp_tool record exists in the given workspace.
461→ */
462→export async function toolExistsInWorkspace(
463→  surreal: Surreal,
464→  toolRecord: RecordId<"mcp_tool", string>,
465→  workspaceRecord: RecordId<"workspace", string>,
466→): Promise<boolean> {
