473→
474→/**
475→ * Create a can_use grant edge between identity and tool.
476→ * Uses RELATE for TYPE RELATION tables (per surrealdb.md).
477→ */
478→export async function createGrant(
479→  surreal: Surreal,
480→  identityRecord: RecordId<"identity", string>,
481→  toolRecord: RecordId<"mcp_tool", string>,
482→  maxCallsPerHour?: number,
483→): Promise<void> {
484→  const setClause = maxCallsPerHour !== undefined
485→    ? `SET granted_at = time::now(), max_calls_per_hour = $maxCallsPerHour`
486→    : `SET granted_at = time::now()`;
487→
488→  await surreal.query(
489→    `RELATE $identity->can_use->$tool ${setClause};`,
490→    { identity: identityRecord, tool: toolRecord, maxCallsPerHour },
491→  );
492→}
493→
494→/**
495→ * List all grants (can_use edges) for a tool, with identity details.
496→ */
497→export async function listGrantsForTool(
498→  surreal: Surreal,
499→  toolRecord: RecordId<"mcp_tool", string>,
500→): Promise<GrantDetailRow[]> {
501→  const results = await surreal.query<[GrantDetailRow[]]>(
502→    `SELECT in.id AS identity_id, in.name AS identity_name, max_calls_per_hour, granted_at FROM can_use WHERE out = $tool ORDER BY granted_at DESC;`,
503→    { tool: toolRecord },
504→  );
505→  return results[0] ?? [];
506→}
507→
508→/**
509→ * Fetch a policy record by ID. Returns undefined if not found.
510→ */
511→export async function getPolicyById(
512→  surreal: Surreal,
513→  policyRecord: RecordId<"policy", string>,
514→): Promise<{ status: string } | undefined> {
515→  const results = await surreal.query<[Array<{ status: string }>]>(
516→    `SELECT status FROM $policy;`,
517→    { policy: policyRecord },
518→  );
519→  return (results[0] ?? [])[0];
520→}
521→
522→/**
523→ * Create a governs_tool RELATION edge between a policy and a tool.
524→ * Uses RELATE for TYPE RELATION tables (per surrealdb.md).
525→ */
526→export async function createGovernanceEdge(
527→  surreal: Surreal,
