): Promise<boolean> {
  const results = await surreal.query<[Array<{ id: RecordId }>]>(
    `SELECT id FROM credential_provider WHERE workspace = $ws AND name = $name LIMIT 1;`,
    { ws: workspaceRecord, name },
  );
  return (results[0] ?? []).length > 0;
}

/**
 * Find an existing credential_provider by discovery_source URL in a workspace.
 * Used to deduplicate providers created via OAuth discovery.
 */
export async function findProviderByDiscoverySource(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  discoverySource: string,
): Promise<CredentialProviderRecord | undefined> {
  const results = await surreal.query<[CredentialProviderRecord[]]>(
    `SELECT * FROM credential_provider WHERE workspace = $ws AND discovery_source = $src LIMIT 1;`,
    { ws: workspaceRecord, src: discoverySource },
  );
  return (results[0] ?? [])[0];
}

/**
 * Create a credential_provider record.
 */
export async function createProvider(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
  content: Record<string, unknown>,
): Promise<CredentialProviderRecord> {
  const providerId = crypto.randomUUID();
  const providerRecord = new RecordId("credential_provider", providerId);

  const fullContent = {
    ...content,
    workspace: workspaceRecord,
    created_at: new Date(),
  };

  await surreal.query(`CREATE $provider CONTENT $content;`, {
    provider: providerRecord,
    content: fullContent,
  });

  return {
    id: providerRecord,
    ...fullContent,
  } as unknown as CredentialProviderRecord;
}

/**
 * Update a credential_provider with client registration fields from DCR.
 */
export async function updateProviderClientRegistration(
  surreal: Surreal,
  providerRecord: RecordId<"credential_provider", string>,
  clientId: string,
  clientSecretEncrypted?: string,
  authServerUrl?: string,
): Promise<void> {
  const setParts = ["client_id = $clientId"];
  const bindings: Record<string, unknown> = { provider: providerRecord, clientId };

  if (clientSecretEncrypted) {
    setParts.push("client_secret_encrypted = $secret");
    bindings.secret = clientSecretEncrypted;
  }
  if (authServerUrl) {
    setParts.push("auth_server_url = $authServerUrl");
    bindings.authServerUrl = authServerUrl;
  }

  await surreal.query(
    `UPDATE $provider SET ${setParts.join(", ")};`,
    bindings,
  );
}

