// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type GrantDetail = {
  identity_id: string;
  identity_name: string;
  max_calls_per_hour?: number;
  granted_at: string;
};

export type GovernancePolicyDetail = {
  policy_title: string;
  policy_status: string;
  conditions?: string;
  max_per_call?: number;
