 21→// ---------------------------------------------------------------------------
 22→// Response mapping -- DB record to API shape
 23→// ---------------------------------------------------------------------------
 24→
 25→function toToolListItem(row: ToolWithCountsRow): ToolListItem {
 26→  const item: ToolListItem = {
 27→    id: row.id.id as string,
 28→    name: row.name,
 29→    toolkit: row.toolkit,
 30→    description: row.description,
 31→    risk_level: row.risk_level as ToolListItem["risk_level"],
 32→    status: row.status as ToolListItem["status"],
 33→    grant_count: row.grant_count,
 34→    governance_count: row.governance_count,
 35→    created_at: row.created_at instanceof Date
 36→      ? row.created_at.toISOString()
 37→      : String(row.created_at),
 38→  };
 39→
 40→  return item;
 41→}
 42→
 43→function toGrantDetail(row: GrantDetailRow): GrantDetail {
 44→  return {
 45→    identity_id: row.identity_id.id as string,
 46→    identity_name: row.identity_name,
 47→    max_calls_per_hour: row.max_calls_per_hour,
 48→    granted_at: row.granted_at instanceof Date
 49→      ? row.granted_at.toISOString()
 50→      : String(row.granted_at),
 51→  };
 52→}
 53→
 54→function toGovernancePolicyDetail(row: GovernancePolicyDetailRow): GovernancePolicyDetail {
 55→  return {
 56→    policy_title: row.policy_title,
 57→    policy_status: row.policy_status,
 58→    conditions: row.conditions,
 59→    max_per_call: row.max_per_call,
 60→    max_per_day: row.max_per_day,
 61→  };
 62→}
