 64→// ---------------------------------------------------------------------------
 65→// Route handlers
 66→// ---------------------------------------------------------------------------
 67→
 68→export function createToolRouteHandlers(deps: ServerDependencies) {
 69→  async function handleListTools(
 70→    workspaceId: string,
 71→    _request: Request,
 72→  ): Promise<Response> {
 73→    let workspaceRecord: RecordId<"workspace", string>;
 74→    try {
 75→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 76→    } catch (error) {
 77→      if (error instanceof HttpError) {
 78→        return jsonError(error.message, error.status);
 79→      }
 80→      log.error("tool.list", "Failed to resolve workspace", error, { workspaceId });
 81→      return jsonError("internal error", 500);
 82→    }
 83→
 84→    const rows = await listToolsWithCounts(deps.surreal, workspaceRecord);
 85→    const tools = rows.map(toToolListItem);
 86→    return jsonResponse({ tools }, 200);
 87→  }
 88→
 89→  async function handleGetToolDetail(
 90→    workspaceId: string,
 91→    toolId: string,
 92→    _request: Request,
 93→  ): Promise<Response> {
 94→    let workspaceRecord: RecordId<"workspace", string>;
 95→    try {
 96→      workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 97→    } catch (error) {
 98→      if (error instanceof HttpError) {
 99→        return jsonError(error.message, error.status);
100→      }
101→      log.error("tool.detail", "Failed to resolve workspace", error, { workspaceId });
102→      return jsonError("internal error", 500);
103→    }
104→
105→    const toolRecord = new RecordId("mcp_tool", toolId);
106→    const result = await getToolDetail(deps.surreal, toolRecord, workspaceRecord);
107→
108→    if (!result) {
109→      return jsonError("Tool not found", 404);
110→    }
111→
112→    const { tool, grants, governancePolicies } = result;
113→
114→    const grantCount = grants.length;
115→    const governanceCount = governancePolicies.length;
116→
117→    const detail: ToolDetail = {
118→      id: tool.id.id as string,
119→      name: tool.name,
120→      toolkit: tool.toolkit,
121→      description: tool.description,
122→      risk_level: tool.risk_level as ToolListItem["risk_level"],
123→      status: tool.status as ToolListItem["status"],
124→      grant_count: grantCount,
125→      governance_count: governanceCount,
126→      created_at: tool.created_at instanceof Date
127→        ? tool.created_at.toISOString()
128→        : String(tool.created_at),
129→      input_schema: tool.input_schema,
130→      output_schema: tool.output_schema,
131→      grants: grants.map(toGrantDetail),
132→      governance_policies: governancePolicies.map(toGovernancePolicyDetail),
133→    };
134→
135→    return jsonResponse(detail, 200);
136→  }
137→
138→  return { handleListTools, handleGetToolDetail };
139→}
