 39→  { id: "accounts", label: "Accounts" },
 40→] as const;
 41→
 42→export const TOOL_REGISTRY_TABS: readonly ToolRegistryTab[] = [
 43→  ...PRIMARY_TABS,
 44→  ...ADVANCED_TABS,
 45→] as const;
 46→
 47→const VALID_TAB_IDS = new Set<string>(TOOL_REGISTRY_TABS.map((t) => t.id));
 48→const DEFAULT_TAB: ToolRegistryTabId = "tools";
