 10→export type BadgeViewModel = {
 11→  label: string;
 12→  variant: "default" | "secondary" | "destructive" | "outline";
 13→  className?: string;
 14→};
 15→
 16→export type ToolRowViewModel = {
 17→  id: string;
 18→  name: string;
 19→  truncatedDescription: string;
 20→  riskBadge: BadgeViewModel;
 21→  statusBadge: BadgeViewModel;
 22→  provenanceBadge: BadgeViewModel;
 23→  grantCount: number;
 24→  governanceCount: number;
 25→  isGoverned: boolean;
 26→  providerName: string;
 27→};
 28→
 29→export type ToolGroupViewModel = {
 30→  toolkit: string;
 31→  toolCount: number;
 32→  rows: ToolRowViewModel[];
 33→};
 34→
 35→export type ToolTableViewModel = {
 36→  groups: ToolGroupViewModel[];
 37→  showEmptyState: boolean;
 38→  showEmptySearch: boolean;
 39→  emptyStateMessage: string;
 40→  emptySearchMessage: string;
 41→};
