 54→// ---------------------------------------------------------------------------
 55→// Badge derivation functions
 56→// ---------------------------------------------------------------------------
 57→
 58→const RISK_BADGES: Record<string, BadgeViewModel> = {
 59→  low: { label: "Low", variant: "outline", className: "text-green-600 border-green-300" },
 60→  medium: { label: "Medium", variant: "outline", className: "text-amber-600 border-amber-300" },
 61→  high: { label: "High", variant: "outline", className: "text-red-600 border-red-300" },
 62→  critical: { label: "Critical", variant: "destructive" },
 63→};
 64→
 65→export function deriveRiskBadge(riskLevel: string): BadgeViewModel {
 66→  return RISK_BADGES[riskLevel] ?? { label: riskLevel, variant: "outline" };
 67→}
 68→
 69→const STATUS_BADGES: Record<string, BadgeViewModel> = {
 70→  active: { label: "Active", variant: "default" },
 71→  disabled: { label: "Disabled", variant: "secondary" },
 72→};
 73→
 74→export function deriveStatusBadge(status: string): BadgeViewModel {
 75→  return STATUS_BADGES[status] ?? { label: status, variant: "outline" };
 76→}
 77→
 78→export function deriveProvenanceBadge(providerName: string): BadgeViewModel {
 79→  if (providerName === "manual") {
 80→    return { label: "Manual", variant: "secondary" };
 81→  }
 82→  return { label: providerName, variant: "outline" };
 83→}
 84→
 85→// ---------------------------------------------------------------------------
 86→// Description truncation
 87→// ---------------------------------------------------------------------------
 88→
 89→const MAX_DESCRIPTION_LENGTH = 100;
 90→
 91→function truncateDescription(description: string): string {
 92→  if (description.length <= MAX_DESCRIPTION_LENGTH) return description;
 93→  return `${description.slice(0, MAX_DESCRIPTION_LENGTH)}...`;
 94→}
 95→
 96→// ---------------------------------------------------------------------------
 97→// Row derivation
 98→// ---------------------------------------------------------------------------
 99→
100→function toToolRow(tool: ToolListItem): ToolRowViewModel {
101→  return {
102→    id: tool.id,
103→    name: tool.name,
104→    truncatedDescription: truncateDescription(tool.description),
105→    riskBadge: deriveRiskBadge(tool.risk_level),
106→    statusBadge: deriveStatusBadge(tool.status),
107→    provenanceBadge: deriveProvenanceBadge(tool.provider_name),
108→    grantCount: tool.grant_count,
109→    governanceCount: tool.governance_count,
110→    isGoverned: tool.governance_count > 0,
111→    providerName: tool.provider_name,
112→  };
113→}
114→
115→// ---------------------------------------------------------------------------
116→// Filtering
117→// ---------------------------------------------------------------------------
118→
119→function matchesSearchText(tool: ToolListItem, searchText: string): boolean {
120→  if (searchText === "") return true;
121→  const lowerSearch = searchText.toLowerCase();
122→  return (
123→    tool.name.toLowerCase().includes(lowerSearch) ||
124→    tool.description.toLowerCase().includes(lowerSearch)
125→  );
126→}
127→
128→export function filterTools(
129→  tools: ToolListItem[],
130→  filters: ToolTableFilters,
131→): ToolListItem[] {
132→  return tools.filter((tool) => {
133→    if (filters.status && tool.status !== filters.status) return false;
134→    if (filters.riskLevel && tool.risk_level !== filters.riskLevel) return false;
135→    if (!matchesSearchText(tool, filters.searchText)) return false;
136→    return true;
137→  });
138→}
139→
140→// ---------------------------------------------------------------------------
141→// Grouping
142→// ---------------------------------------------------------------------------
143→
144→export function groupToolsByToolkit(tools: ToolListItem[]): ToolGroupViewModel[] {
145→  const groupMap = new Map<string, ToolListItem[]>();
146→
147→  for (const tool of tools) {
148→    const existing = groupMap.get(tool.toolkit);
149→    if (existing) {
150→      existing.push(tool);
151→    } else {
152→      groupMap.set(tool.toolkit, [tool]);
153→    }
154→  }
155→
156→  return Array.from(groupMap.entries()).map(([toolkit, groupTools]) => ({
157→    toolkit,
158→    toolCount: groupTools.length,
159→    rows: groupTools.map(toToolRow),
160→  }));
161→}
162→
163→// ---------------------------------------------------------------------------
164→// Main view model derivation
165→// ---------------------------------------------------------------------------
166→
167→const EMPTY_STATE_MESSAGE = "No tools discovered yet.";
168→const EMPTY_SEARCH_MESSAGE = "No tools match your search";
169→
170→export function deriveToolTableViewModel(input: ToolTableInput): ToolTableViewModel {
171→  const filteredTools = filterTools(input.tools, input.filters);
172→  const groups = groupToolsByToolkit(filteredTools);
173→
174→  const hasTools = input.tools.length > 0;
175→  const hasFilteredResults = filteredTools.length > 0;
176→  const hasActiveFilters =
177→    input.filters.searchText !== "" ||
178→    input.filters.status !== undefined ||
179→    input.filters.riskLevel !== undefined;
180→
181→  return {
182→    groups,
183→    showEmptyState: !hasTools,
184→    showEmptySearch: hasTools && !hasFilteredResults && hasActiveFilters,
185→    emptyStateMessage: EMPTY_STATE_MESSAGE,
186→    emptySearchMessage: EMPTY_SEARCH_MESSAGE,
187→  };
188→}
