  3→// ---------------------------------------------------------------------------
  4→// Types
  5→// ---------------------------------------------------------------------------
  6→
  7→export type GrantDetail = {
  8→  identity_id: string;
  9→  identity_name: string;
 10→  max_calls_per_hour?: number;
 11→  granted_at: string;
 12→};
 13→
 14→export type GovernancePolicyDetail = {
 15→  policy_title: string;
 16→  policy_status: string;
 17→  conditions?: string;
 18→  max_per_call?: number;
 19→  max_per_day?: number;
 20→};
 21→
 22→export type ToolDetailData = {
 23→  id: string;
 24→  name: string;
 25→  toolkit: string;
 26→  description: string;
 27→  risk_level: string;
 28→  status: string;
 29→  grant_count: number;
 30→  governance_count: number;
 31→  created_at: string;
 32→  input_schema: Record<string, unknown>;
 33→  output_schema?: Record<string, unknown>;
 34→  grants: GrantDetail[];
 35→  governance_policies: GovernancePolicyDetail[];
 36→};
 37→
 38→export type ToolDetailViewState =
 39→  | { state: "loading" }
 40→  | { state: "error"; error: string }
 41→  | { state: "loaded"; data: ToolDetailData };
 42→
 43→// ---------------------------------------------------------------------------
 44→// View model types
 45→// ---------------------------------------------------------------------------
 46→
 47→export type GrantRowViewModel = {
 48→  identityName: string;
 49→  rateLimitDisplay: string;
 50→  grantedAt: string;
 51→};
 52→
 53→export type GovernanceRowViewModel = {
 54→  policyTitle: string;
 55→  conditionsDisplay: string;
 56→  maxPerCallDisplay: string;
 57→  maxPerDayDisplay: string;
 58→};
 59→
 60→export type ToolDetailViewModel =
 61→  | { tag: "loading" }
 62→  | { tag: "error"; errorMessage: string }
 63→  | {
 64→      tag: "loaded";
 65→      formattedInputSchema: string;
 66→      grantRows: GrantRowViewModel[];
 67→      governanceRows: GovernanceRowViewModel[];
 68→      showEmptyGrants: boolean;
 69→      showEmptyGovernance: boolean;
 70→    };
 71→
 72→// ---------------------------------------------------------------------------
 73→// Grant row derivation
 74→// ---------------------------------------------------------------------------
 75→
 76→function formatRateLimit(maxCallsPerHour?: number): string {
 77→  if (maxCallsPerHour === undefined) return "Unlimited";
 78→  return `${maxCallsPerHour}/hr`;
 79→}
 80→
 81→function toGrantRow(grant: GrantDetail): GrantRowViewModel {
 82→  return {
 83→    identityName: grant.identity_name,
 84→    rateLimitDisplay: formatRateLimit(grant.max_calls_per_hour),
 85→    grantedAt: grant.granted_at,
 86→  };
 87→}
 88→
 89→// ---------------------------------------------------------------------------
 90→// Governance row derivation
 91→// ---------------------------------------------------------------------------
 92→
 93→function formatOptionalNumber(value?: number): string {
 94→  if (value === undefined) return "--";
 95→  return String(value);
 96→}
 97→
 98→function toGovernanceRow(policy: GovernancePolicyDetail): GovernanceRowViewModel {
 99→  return {
100→    policyTitle: policy.policy_title,
101→    conditionsDisplay: policy.conditions ?? "None",
102→    maxPerCallDisplay: formatOptionalNumber(policy.max_per_call),
103→    maxPerDayDisplay: formatOptionalNumber(policy.max_per_day),
104→  };
105→}
106→
107→// ---------------------------------------------------------------------------
108→// View model derivation
109→// ---------------------------------------------------------------------------
110→
111→export function deriveToolDetailViewModel(
112→  viewState: ToolDetailViewState,
113→): ToolDetailViewModel {
114→  if (viewState.state === "loading") {
115→    return { tag: "loading" };
116→  }
117→
118→  if (viewState.state === "error") {
119→    return { tag: "error", errorMessage: viewState.error };
120→  }
121→
122→  const { data } = viewState;
123→  const grantRows = data.grants.map(toGrantRow);
124→  const governanceRows = data.governance_policies.map(toGovernanceRow);
125→
126→  return {
127→    tag: "loaded",
128→    formattedInputSchema: JSON.stringify(data.input_schema, null, 2),
129→    grantRows,
130→    governanceRows,
131→    showEmptyGrants: grantRows.length === 0,
132→    showEmptyGovernance: governanceRows.length === 0,
133→  };
134→}
