136→// ---------------------------------------------------------------------------
137→// React component
138→// ---------------------------------------------------------------------------
139→
140→type ToolDetailPanelProps = {
141→  toolId: string;
142→};
143→
144→export function ToolDetailPanel({ toolId }: ToolDetailPanelProps) {
145→  const { data, isLoading, error } = useToolDetail(toolId);
146→
147→  const viewState: ToolDetailViewState = isLoading
148→    ? { state: "loading" }
149→    : error
150→      ? { state: "error", error }
151→      : data
152→        ? { state: "loaded", data }
153→        : { state: "loading" };
154→
