24→/** Pure function: builds the API URL for fetching tools. */
25→export function buildToolsUrl(workspaceId: string): string {
26→  return `/api/workspaces/${encodeURIComponent(workspaceId)}/tools`;
27→}
28→
29→export function useTools(): UseToolsReturn {
30→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
31→  const [tools, setTools] = useState<ToolListItem[]>([]);
32→  const [isLoading, setIsLoading] = useState(false);
33→  const [error, setError] = useState<string | undefined>();
34→
35→  const fetchTools = useCallback(async () => {
36→    if (!workspaceId) return;
37→
38→    setIsLoading(true);
39→    setError(undefined);
40→
41→    try {
42→      const url = buildToolsUrl(workspaceId);
43→      const response = await fetch(url);
44→      if (!response.ok) {
45→        const body = await response.text();
46→        throw new Error(body);
47→      }
48→      const data = (await response.json()) as { tools: ToolListItem[] };
49→      setTools(data.tools);
50→    } catch (err) {
51→      setError(err instanceof Error ? err.message : "Failed to load tools");
52→    } finally {
53→      setIsLoading(false);
54→    }
55→  }, [workspaceId]);
56→
57→  useEffect(() => {
58→    if (!workspaceId) return;
59→    void fetchTools();
60→  }, [workspaceId, fetchTools]);
61→
62→  const refresh = useCallback(() => {
63→    void fetchTools();
64→  }, [fetchTools]);
65→
66→  return { tools, isLoading, error, refresh };
