143→        const payload: Record<string, unknown> = {
144→          name: formData.name,
145→          url: formData.url,
146→          transport: formData.transport,
147→          auth_mode: formData.auth_mode,
148→        };
149→        if (formData.auth_mode === "static_headers") {
150→          payload.static_headers = formData.static_headers;
151→        }
152→        if (formData.auth_mode === "provider" && formData.credentialProviderId) {
153→          payload.provider_id = formData.credentialProviderId;
154→        }
155→        const response = await fetch(
156→          `/api/workspaces/${encodeURIComponent(workspaceId)}/mcp-servers`,
157→          {
158→            method: "POST",
159→            headers: { "Content-Type": "application/json" },
160→            body: JSON.stringify(payload),
161→          },
162→        );
163→        if (!response.ok) {
164→          const text = await response.text();
165→          try {
166→            const body = JSON.parse(text) as { error?: string };
