171→        }
172→        const data = (await response.json()) as { authorization_url?: string };
173→
174→        // If the server supports OAuth, the backend auto-discovered and generated
175→        // an authorization URL — open it so the user can authorize immediately.
176→        if (data.authorization_url) {
177→          window.open(data.authorization_url, "_blank");
178→        }
179→
180→        refreshMcpServers();
181→        refreshProviders();
182→        return {};
183→      } catch {
184→        return { error: "Network error" };
