438→                  className="h-8 rounded-md border px-2 text-sm"
439→                >
440→                  <option value="">All risk levels</option>
441→                  <option value="low">Low</option>
442→                  <option value="medium">Medium</option>
443→                  <option value="high">High</option>
444→                  <option value="critical">Critical</option>
445→                </select>
