import { describe, it, expect, mock } from "bun:test";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import type { ToolListItem } from "../../hooks/use-tools";

// Mock the hook (not the whole module) to avoid poisoning other test files
mock.module("../../hooks/use-tool-detail", () => ({
  useToolDetail: (toolId: string) => ({
    data: { id: toolId, name: "mock", toolkit: "mock", description: "", risk_level: "low", status: "active", grant_count: 0, governance_count: 0, created_at: "", input_schema: {}, grants: [], governance_policies: [] },
    isLoading: false,
    error: undefined,
  }),
}));
mock.module("../ui/button", () => ({
  Button: (props: Record<string, unknown>) => props.children,
}));

// Import after mock
const { ToolTable, groupToolsByServer, deriveToolTableViewModel, filterTools } = await import("./ToolTable");

function makeTool(overrides: Partial<ToolListItem> = {}): ToolListItem {
  return {
    id: "t1",
    name: "read_file",
    toolkit: "filesystem",
    description: "Read a file from disk",
    risk_level: "low",
    status: "active",
    grant_count: 2,
    governance_count: 0,
    provider_name: "github-server",
    source_server_id: "srv1",
    source_server_name: "Linear",
    created_at: "2026-01-01T00:00:00Z",
    ...overrides,
  };
}

const NO_FILTERS = { searchText: "" };

describe("ToolTable", () => {
  // -------------------------------------------------------------------------
  // Server-based grouping
  // -------------------------------------------------------------------------

  it("renders tools grouped by MCP server with counts", () => {
    const tools = [
      makeTool({ id: "t1", name: "read_file", source_server_id: "srv1", source_server_name: "Linear" }),
      makeTool({ id: "t2", name: "write_file", source_server_id: "srv1", source_server_name: "Linear" }),
      makeTool({ id: "t3", name: "search", source_server_id: "srv2", source_server_name: "GitHub" }),
    ];
    render(<ToolTable tools={tools} filters={NO_FILTERS} />);

    expect(screen.getByText("Linear")).toBeInTheDocument();
    expect(screen.getByText("GitHub")).toBeInTheDocument();
    // Group headers show server name followed by count badge
    const badges = screen.getAllByText((_, el) =>
      el?.getAttribute("data-slot") === "badge" &&
      el?.getAttribute("data-variant") === "secondary" &&
      (el?.textContent === "2" || el?.textContent === "1"),
    );
    expect(badges.length).toBe(2);
  });

  it("groups tools without a server under Ungrouped", () => {
    const tools = [
      makeTool({ id: "t1", name: "manual_tool", source_server_id: undefined, source_server_name: undefined }),
    ];
    render(<ToolTable tools={tools} filters={NO_FILTERS} />);
    expect(screen.getByText("Ungrouped")).toBeInTheDocument();
  });

  it("shows server groups before ungrouped", () => {
    const tools = [
      makeTool({ id: "t1", name: "manual_tool", source_server_id: undefined, source_server_name: undefined }),
      makeTool({ id: "t2", name: "linear_tool", source_server_id: "srv1", source_server_name: "Linear" }),
    ];
    render(<ToolTable tools={tools} filters={NO_FILTERS} />);

    const headers = screen.getAllByText((_, el) =>
      el?.tagName === "SPAN" &&
      el?.classList.contains("font-semibold") &&
      (el?.textContent === "Linear" || el?.textContent === "Ungrouped"),
    );
    expect(headers[0].textContent).toBe("Linear");
    expect(headers[1].textContent).toBe("Ungrouped");
  });

  // -------------------------------------------------------------------------
  // Badges
  // -------------------------------------------------------------------------

  it("shows risk level badges", () => {
    const tools = [
      makeTool({ id: "t1", risk_level: "low" }),
      makeTool({ id: "t2", risk_level: "critical" }),
    ];
    render(<ToolTable tools={tools} filters={NO_FILTERS} />);
    expect(screen.getByText("Low")).toBeInTheDocument();
    expect(screen.getByText("Critical")).toBeInTheDocument();
  });

  it("shows status badges", () => {
    const tools = [
      makeTool({ id: "t1", status: "active" }),
      makeTool({ id: "t2", status: "disabled" }),
    ];
    render(<ToolTable tools={tools} filters={NO_FILTERS} />);
    expect(screen.getByText("Active")).toBeInTheDocument();
    expect(screen.getByText("Disabled")).toBeInTheDocument();
  });

  // -------------------------------------------------------------------------
  // Empty states
  // -------------------------------------------------------------------------

  it("shows empty state when no tools", () => {
    render(<ToolTable tools={[]} filters={NO_FILTERS} />);
    expect(screen.getByText("No tools discovered yet.")).toBeInTheDocument();
  });

  it("shows empty search when filters match nothing", () => {
    const tools = [makeTool()];
    render(<ToolTable tools={tools} filters={{ searchText: "nonexistent-xyz" }} />);
    expect(screen.getByText("No tools match your search")).toBeInTheDocument();
  });

  // -------------------------------------------------------------------------
  // Governance
  // -------------------------------------------------------------------------

  it("shows shield for governed tools", () => {
    render(<ToolTable tools={[makeTool({ governance_count: 3 })]} filters={NO_FILTERS} />);
    expect(screen.getByLabelText("shield")).toBeInTheDocument();
  });

  it("does not show shield for ungoverned tools", () => {
    render(<ToolTable tools={[makeTool({ governance_count: 0 })]} filters={NO_FILTERS} />);
    expect(screen.queryByLabelText("shield")).not.toBeInTheDocument();
  });

  // -------------------------------------------------------------------------
  // Expand / collapse
  // -------------------------------------------------------------------------

  it("clicking row expands detail panel", async () => {
    const user = userEvent.setup();
    render(<ToolTable tools={[makeTool({ id: "t1", name: "read_file" })]} filters={NO_FILTERS} />);

    await user.click(screen.getByText("read_file"));
    expect(screen.getByTestId("detail-t1")).toBeInTheDocument();
  });

  it("clicking expanded row collapses detail panel", async () => {
    const user = userEvent.setup();
    render(<ToolTable tools={[makeTool({ id: "t1", name: "read_file" })]} filters={NO_FILTERS} />);

    await user.click(screen.getByText("read_file"));
    expect(screen.getByTestId("detail-t1")).toBeInTheDocument();

    await user.click(screen.getByText("read_file"));
    expect(screen.queryByTestId("detail-t1")).not.toBeInTheDocument();
  });

  it("truncates descriptions longer than 100 chars", () => {
    const longDesc = "A".repeat(120);
    render(<ToolTable tools={[makeTool({ description: longDesc })]} filters={NO_FILTERS} />);
    expect(screen.getByText(`${"A".repeat(100)}...`)).toBeInTheDocument();
  });
});

// ---------------------------------------------------------------------------
// Pure function unit tests
// ---------------------------------------------------------------------------

describe("groupToolsByServer", () => {
  it("groups tools by source_server_id", () => {
    const tools = [
      makeTool({ id: "t1", source_server_id: "srv1", source_server_name: "Linear" }),
      makeTool({ id: "t2", source_server_id: "srv1", source_server_name: "Linear" }),
      makeTool({ id: "t3", source_server_id: "srv2", source_server_name: "GitHub" }),
    ];
    const groups = groupToolsByServer(tools);

    expect(groups.length).toBe(2);
    expect(groups[0].label).toBe("GitHub");
    expect(groups[0].rows.length).toBe(1);
    expect(groups[1].label).toBe("Linear");
    expect(groups[1].rows.length).toBe(2);
  });

  it("puts ungrouped tools in an Ungrouped group at the end", () => {
    const tools = [
      makeTool({ id: "t1", source_server_id: "srv1", source_server_name: "Linear" }),
      makeTool({ id: "t2", source_server_id: undefined, source_server_name: undefined }),
    ];
    const groups = groupToolsByServer(tools);

    expect(groups.length).toBe(2);
    expect(groups[0].label).toBe("Linear");
    expect(groups[0].serverId).toBe("srv1");
    expect(groups[1].label).toBe("Ungrouped");
    expect(groups[1].serverId).toBeUndefined();
  });

  it("returns empty array for no tools", () => {
    expect(groupToolsByServer([]).length).toBe(0);
  });

  it("sorts server groups alphabetically by name", () => {
    const tools = [
      makeTool({ id: "t1", source_server_id: "srv2", source_server_name: "Zeta" }),
      makeTool({ id: "t2", source_server_id: "srv1", source_server_name: "Alpha" }),
    ];
    const groups = groupToolsByServer(tools);
    expect(groups[0].label).toBe("Alpha");
    expect(groups[1].label).toBe("Zeta");
  });
});

describe("filterTools", () => {
  it("filters by search text in name", () => {
    const tools = [
      makeTool({ id: "t1", name: "read_file", description: "Read a file" }),
      makeTool({ id: "t2", name: "write_file", description: "Write a file" }),
    ];
    const result = filterTools(tools, { searchText: "read" });
    expect(result.length).toBe(1);
    expect(result[0].name).toBe("read_file");
  });

  it("filters by status", () => {
    const tools = [
      makeTool({ id: "t1", status: "active" }),
      makeTool({ id: "t2", status: "disabled" }),
    ];
    const result = filterTools(tools, { searchText: "", status: "disabled" });
    expect(result.length).toBe(1);
    expect(result[0].status).toBe("disabled");
  });

  it("filters by risk level", () => {
    const tools = [
      makeTool({ id: "t1", risk_level: "low" }),
      makeTool({ id: "t2", risk_level: "high" }),
    ];
    const result = filterTools(tools, { searchText: "", riskLevel: "high" });
    expect(result.length).toBe(1);
    expect(result[0].risk_level).toBe("high");
  });
});

describe("deriveToolTableViewModel", () => {
  it("sets showEmptyState when no tools provided", () => {
    const vm = deriveToolTableViewModel({ tools: [], filters: NO_FILTERS });
    expect(vm.showEmptyState).toBe(true);
    expect(vm.showEmptySearch).toBe(false);
  });

  it("sets showEmptySearch when filters exclude all tools", () => {
    const vm = deriveToolTableViewModel({
      tools: [makeTool()],
      filters: { searchText: "nonexistent" },
    });
    expect(vm.showEmptyState).toBe(false);
    expect(vm.showEmptySearch).toBe(true);
  });

  it("produces groups from filtered tools", () => {
    const vm = deriveToolTableViewModel({
      tools: [
        makeTool({ id: "t1", source_server_id: "srv1", source_server_name: "Linear" }),
        makeTool({ id: "t2", source_server_id: "srv2", source_server_name: "GitHub" }),
      ],
      filters: NO_FILTERS,
    });
    expect(vm.groups.length).toBe(2);
  });
});

import { useState } from "react";
import { Badge } from "../ui/badge";
import type { ToolListItem } from "../../hooks/use-tools";
import { ToolDetailPanel, type ToolDetailActions } from "./ToolDetailPanel";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type BadgeViewModel = {
  label: string;
  variant: "default" | "secondary" | "destructive" | "outline";
  className?: string;
};

export type ToolRowViewModel = {
  id: string;
  name: string;
  truncatedDescription: string;
  riskBadge: BadgeViewModel;
  statusBadge: BadgeViewModel;
  grantCount: number;
  governanceCount: number;
  isGoverned: boolean;
};

export type ToolGroupViewModel = {
  /** Display label for the group header. Server name or "Ungrouped". */
  label: string;
  /** Server ID if tools belong to an MCP server, undefined for manual tools. */
  serverId?: string;
  toolCount: number;
  rows: ToolRowViewModel[];
};

export type ToolTableViewModel = {
  groups: ToolGroupViewModel[];
  showEmptyState: boolean;
  showEmptySearch: boolean;
  emptyStateMessage: string;
  emptySearchMessage: string;
};

export type ToolTableFilters = {
  searchText: string;
  status?: string;
  riskLevel?: string;
};

export type ToolTableInput = {
  tools: ToolListItem[];
  filters: ToolTableFilters;
};

// ---------------------------------------------------------------------------
// Badge derivation functions
// ---------------------------------------------------------------------------

const RISK_BADGES: Record<string, BadgeViewModel> = {
  low: { label: "Low", variant: "outline", className: "text-green-600 border-green-300" },
  medium: { label: "Medium", variant: "outline", className: "text-amber-600 border-amber-300" },
  high: { label: "High", variant: "outline", className: "text-red-600 border-red-300" },
  critical: { label: "Critical", variant: "destructive" },
};

export function deriveRiskBadge(riskLevel: string): BadgeViewModel {
  return RISK_BADGES[riskLevel] ?? { label: riskLevel, variant: "outline" };
}

const STATUS_BADGES: Record<string, BadgeViewModel> = {
  active: { label: "Active", variant: "default" },
  disabled: { label: "Disabled", variant: "secondary" },
};

export function deriveStatusBadge(status: string): BadgeViewModel {
  return STATUS_BADGES[status] ?? { label: status, variant: "outline" };
}

// ---------------------------------------------------------------------------
// Description truncation
// ---------------------------------------------------------------------------

const MAX_DESCRIPTION_LENGTH = 100;

function truncateDescription(description: string): string {
  if (description.length <= MAX_DESCRIPTION_LENGTH) return description;
  return `${description.slice(0, MAX_DESCRIPTION_LENGTH)}...`;
}

// ---------------------------------------------------------------------------
// Row derivation
// ---------------------------------------------------------------------------

function toToolRow(tool: ToolListItem): ToolRowViewModel {
  return {
    id: tool.id,
    name: tool.name,
    truncatedDescription: truncateDescription(tool.description),
    riskBadge: deriveRiskBadge(tool.risk_level),
    statusBadge: deriveStatusBadge(tool.status),
    grantCount: tool.grant_count,
    governanceCount: tool.governance_count,
    isGoverned: tool.governance_count > 0,
  };
}

// ---------------------------------------------------------------------------
// Filtering
// ---------------------------------------------------------------------------

function matchesSearchText(tool: ToolListItem, searchText: string): boolean {
  if (searchText === "") return true;
  const lowerSearch = searchText.toLowerCase();
  return (
    tool.name.toLowerCase().includes(lowerSearch) ||
    tool.description.toLowerCase().includes(lowerSearch)
  );
}

export function filterTools(
  tools: ToolListItem[],
  filters: ToolTableFilters,
): ToolListItem[] {
  return tools.filter((tool) => {
    if (filters.status && tool.status !== filters.status) return false;
    if (filters.riskLevel && tool.risk_level !== filters.riskLevel) return false;
    if (!matchesSearchText(tool, filters.searchText)) return false;
    return true;
  });
}

// ---------------------------------------------------------------------------
// Grouping — by MCP server
// ---------------------------------------------------------------------------

const UNGROUPED_LABEL = "Ungrouped";

export function groupToolsByServer(tools: ToolListItem[]): ToolGroupViewModel[] {
  const serverGroups = new Map<string, { name: string; id: string; tools: ToolListItem[] }>();
  const ungrouped: ToolListItem[] = [];

  for (const tool of tools) {
    if (tool.source_server_id && tool.source_server_name) {
      const existing = serverGroups.get(tool.source_server_id);
      if (existing) {
        existing.tools.push(tool);
      } else {
        serverGroups.set(tool.source_server_id, {
          name: tool.source_server_name,
          id: tool.source_server_id,
          tools: [tool],
        });
      }
    } else {
      ungrouped.push(tool);
    }
  }

  const groups: ToolGroupViewModel[] = [];

  // Server groups first, sorted by name
  const sorted = Array.from(serverGroups.values()).sort((a, b) =>
    a.name.localeCompare(b.name),
  );
  for (const group of sorted) {
    groups.push({
      label: group.name,
      serverId: group.id,
      toolCount: group.tools.length,
      rows: group.tools.map(toToolRow),
    });
  }

  // Ungrouped tools last
  if (ungrouped.length > 0) {
    groups.push({
      label: UNGROUPED_LABEL,
      toolCount: ungrouped.length,
      rows: ungrouped.map(toToolRow),
    });
  }

  return groups;
}

// ---------------------------------------------------------------------------
// Main view model derivation
// ---------------------------------------------------------------------------

const EMPTY_STATE_MESSAGE = "No tools discovered yet.";
const EMPTY_SEARCH_MESSAGE = "No tools match your search";

export function deriveToolTableViewModel(input: ToolTableInput): ToolTableViewModel {
  const filteredTools = filterTools(input.tools, input.filters);
  const groups = groupToolsByServer(filteredTools);

  const hasTools = input.tools.length > 0;
  const hasFilteredResults = filteredTools.length > 0;
  const hasActiveFilters =
    input.filters.searchText !== "" ||
    input.filters.status !== undefined ||
    input.filters.riskLevel !== undefined;

  return {
    groups,
    showEmptyState: !hasTools,
    showEmptySearch: hasTools && !hasFilteredResults && hasActiveFilters,
    emptyStateMessage: EMPTY_STATE_MESSAGE,
    emptySearchMessage: EMPTY_SEARCH_MESSAGE,
  };
}

// ---------------------------------------------------------------------------
// React: Tool table component
// ---------------------------------------------------------------------------

type ToolTableProps = {
  tools: ToolListItem[];
  filters: ToolTableFilters;
  actions?: ToolDetailActions;
};

export function ToolTable({ tools, filters, actions }: ToolTableProps) {
  const [expandedToolId, setExpandedToolId] = useState<string | undefined>();
  const vm = deriveToolTableViewModel({ tools, filters });

  function handleRowClick(toolId: string) {
    setExpandedToolId((current) => (current === toolId ? undefined : toolId));
  }

  if (vm.showEmptyState) {
    return (
      <div className="flex flex-col items-center gap-3 py-12 text-center">
        <p className="text-sm text-muted-foreground">{vm.emptyStateMessage}</p>
      </div>
    );
  }

  if (vm.showEmptySearch) {
    return (
      <div className="flex flex-col items-center gap-3 py-12 text-center">
        <p className="text-sm text-muted-foreground">{vm.emptySearchMessage}</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-4">
      {vm.groups.map((group) => (
        <div key={group.serverId ?? group.label}>
          <div className="flex items-center gap-2 border-b px-3 py-2">
            <span className="text-sm font-semibold">{group.label}</span>
            <Badge variant="secondary">{group.toolCount}</Badge>
          </div>
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b text-left text-muted-foreground">
                <th className="px-3 py-2 font-medium">Name</th>
                <th className="px-3 py-2 font-medium">Description</th>
                <th className="px-3 py-2 font-medium">Risk</th>
                <th className="px-3 py-2 font-medium">Status</th>
                <th className="px-3 py-2 font-medium">Grants</th>
                <th className="px-3 py-2 font-medium">Governance</th>
              </tr>
            </thead>
            <tbody>
              {group.rows.map((row) => (
                <>
                  <tr
                    key={row.id}
                    className="cursor-pointer border-b hover:bg-muted/50"
                    onClick={() => handleRowClick(row.id)}
                  >
                    <td className="px-3 py-2 font-medium">
                      {row.isGoverned && (
                        <span className="mr-1" title="Governed tool" aria-label="shield">
                          &#x1F6E1;
                        </span>
                      )}
                      {row.name}
                    </td>
                    <td className="px-3 py-2 text-muted-foreground">
                      {row.truncatedDescription}
                    </td>
                    <td className="px-3 py-2">
                      <Badge variant={row.riskBadge.variant} className={row.riskBadge.className}>
                        {row.riskBadge.label}
                      </Badge>
                    </td>
                    <td className="px-3 py-2">
                      <Badge variant={row.statusBadge.variant}>
                        {row.statusBadge.label}
                      </Badge>
                    </td>
                    <td className="px-3 py-2">{row.grantCount}</td>
                    <td className="px-3 py-2">{row.governanceCount}</td>
                  </tr>
                  {expandedToolId === row.id && (
                    <ToolDetailPanel toolId={row.id} toolName={row.name} actions={actions} />
                  )}
                </>
              ))}
            </tbody>
          </table>
        </div>
      ))}
    </div>
  );
}

import { useState } from "react";
import { Badge } from "../ui/badge";
import type { ToolListItem } from "../../hooks/use-tools";
import { ToolDetailPanel, type ToolDetailActions } from "./ToolDetailPanel";

