  1→/**
  2→ * MCP Tool Discovery Service
  3→ *
  4→ * Pure functions for diffing remote MCP server tools against local records,
  5→ * inferring risk levels from MCP annotations, and filtering by selection.
  6→ *
  7→ * Effectful wrappers handle MCP client connections and DB persistence.
  8→ *
  9→ * Pure core (unit-testable):
 10→ *   - inferRiskLevel(annotations) -> ToolRiskLevel
 11→ *   - computeSyncActions(remoteTools, existingTools) -> ToolSyncDetail[]
 12→ *   - filterBySelection(tools, selectedTools?) -> ToolSyncDetail[]
 13→ *
 14→ * Effectful boundary (acceptance-testable):
 15→ *   - discoverTools(deps, server, options) -> DiscoveryResult
 16→ *   - applySyncActions(deps, server, syncDetails) -> SyncApplyResult
 17→ */
 18→import { RecordId, type Surreal } from "surrealdb";
 19→import type { McpClientFactory, ToolListResult } from "./mcp-client";
 20→import type {
 21→  ToolRiskLevel,
 22→  ToolSyncAction,
 23→  ToolSyncDetail,
 24→  McpServerRecord,
 25→  McpTransport,
 26→} from "./types";
 27→import { resolveAuthForMcpServer } from "../proxy/credential-resolver";
 28→
 29→// ---------------------------------------------------------------------------
 30→// Public types for pure functions
 31→// ---------------------------------------------------------------------------
 32→
 33→/**
 34→ * A tool as reported by the remote MCP server (from client.listTools()).
 35→ */
 36→export type RemoteTool = {
 37→  name: string;
 38→  description: string;
 39→  inputSchema: Record<string, unknown>;
 40→  outputSchema?: Record<string, unknown>;
 41→  annotations?: Record<string, unknown>;
 42→};
 43→
 44→/**
 45→ * Minimal shape of an existing local mcp_tool record needed for diffing.
 46→ */
 47→export type ExistingToolRecord = {
 48→  name: string;
 49→  description: string;
 50→  input_schema: Record<string, unknown>;
 51→  output_schema?: Record<string, unknown>;
 52→  risk_level: string;
 53→  status: string;
 54→};
 55→
 56→/**
 57→ * Result of applying sync actions to the database.
 58→ */
 59→export type SyncApplyResult = {
 60→  created: number;
 61→  updated: number;
 62→  disabled: number;
 63→  unchanged: number;
 64→  tools: ToolSyncDetail[];
 65→};
 66→
 67→// ---------------------------------------------------------------------------
 68→// Pure functions
 69→// ---------------------------------------------------------------------------
 70→
 71→/**
 72→ * Infer risk level from MCP tool annotations.
 73→ *
 74→ * Priority:
 75→ *   1. destructiveHint === true  -> "high"
 76→ *   2. readOnlyHint === true     -> "low"
 77→ *   3. idempotentHint === true   -> "low"
 78→ *   4. default                   -> "medium"
 79→ */
 80→export function inferRiskLevel(
 81→  annotations: Record<string, unknown> | undefined,
 82→): ToolRiskLevel {
 83→  if (!annotations) return "medium";
 84→
 85→  if (annotations.destructiveHint === true) return "high";
 86→  if (annotations.readOnlyHint === true) return "low";
 87→  if (annotations.idempotentHint === true) return "low";
 88→
 89→  return "medium";
 90→}
 91→
 92→/**
 93→ * Compute sync actions by diffing remote tools against existing local records.
 94→ *
 95→ * For each remote tool:
 96→ *   - Not in local           -> action: "create"
 97→ *   - In local, schema/desc differs -> action: "update"
 98→ *   - In local, identical    -> action: "unchanged"
 99→ *
100→ * For each local tool NOT in remote (and still active):
101→ *   -> action: "disable"
102→ */
103→export function computeSyncActions(
104→  remoteTools: RemoteTool[],
105→  existingTools: ExistingToolRecord[],
106→): ToolSyncDetail[] {
107→  const existingByName = new Map(
108→    existingTools.map((tool) => [tool.name, tool]),
109→  );
110→  const remoteNames = new Set(remoteTools.map((tool) => tool.name));
111→  const result: ToolSyncDetail[] = [];
112→
113→  // Process remote tools
114→  for (const remote of remoteTools) {
115→    const existing = existingByName.get(remote.name);
116→    const riskLevel = inferRiskLevel(remote.annotations);
117→
118→    if (!existing) {
119→      result.push({
120→        name: remote.name,
121→        description: remote.description,
122→        input_schema: remote.inputSchema,
123→        output_schema: remote.outputSchema,
124→        action: "create",
125→        risk_level: riskLevel,
126→      });
127→      continue;
128→    }
129→
130→    const descriptionChanged = remote.description !== existing.description;
131→    const inputSchemaChanged =
132→      JSON.stringify(remote.inputSchema) !==
133→      JSON.stringify(existing.input_schema);
134→    const outputSchemaChanged =
135→      JSON.stringify(remote.outputSchema) !==
136→      JSON.stringify(existing.output_schema);
137→
138→    const action: ToolSyncAction =
139→      descriptionChanged || inputSchemaChanged || outputSchemaChanged
140→        ? "update"
141→        : "unchanged";
142→
143→    result.push({
144→      name: remote.name,
145→      description: remote.description,
146→      input_schema: remote.inputSchema,
147→      output_schema: remote.outputSchema,
148→      action,
149→      risk_level: riskLevel,
150→    });
151→  }
152→
153→  // Process local-only tools (candidates for disable)
154→  for (const existing of existingTools) {
155→    if (!remoteNames.has(existing.name) && existing.status !== "disabled") {
156→      result.push({
157→        name: existing.name,
158→        description: existing.description,
159→        input_schema: existing.input_schema,
160→        output_schema: existing.output_schema,
161→        action: "disable",
162→        risk_level: existing.risk_level as ToolRiskLevel,
163→      });
164→    }
165→  }
166→
167→  return result;
168→}
169→
170→/**
171→ * Filter sync details to only include tools in the selection list.
172→ * If no selection provided (undefined or empty array), returns all tools.
173→ */
174→export function filterBySelection(
175→  tools: ToolSyncDetail[],
176→  selectedTools: string[] | undefined,
177→): ToolSyncDetail[] {
178→  if (!selectedTools || selectedTools.length === 0) return tools;
179→
180→  const selectedSet = new Set(selectedTools);
181→  return tools.filter((tool) => selectedSet.has(tool.name));
182→}
183→
184→// ---------------------------------------------------------------------------
185→// Effectful functions (DB + MCP client)
186→// ---------------------------------------------------------------------------
187→
188→/** Dependencies for the discovery service. */
189→export type DiscoveryDeps = {
190→  surreal: Surreal;
191→  mcpClientFactory: McpClientFactory;
192→  toolEncryptionKey?: string;
193→};
194→
195→/** Options for the discoverTools function. */
196→export type DiscoverToolsOptions = {
197→  dryRun: boolean;
198→  selectedTools?: string[];
199→};
200→
201→/**
202→ * Convert MCP SDK tool list result to our RemoteTool shape.
203→ */
204→export function toRemoteTools(toolListResult: ToolListResult): RemoteTool[] {
205→  return toolListResult.tools.map((tool) => ({
206→    name: tool.name,
207→    description: tool.description ?? "",
208→    inputSchema: (tool.inputSchema ?? {}) as Record<string, unknown>,
209→    outputSchema: tool.outputSchema as Record<string, unknown> | undefined,
210→    annotations: tool.annotations as Record<string, unknown> | undefined,
211→  }));
212→}
213→
214→/**
215→ * Fetch existing mcp_tool records for a server from SurrealDB.
216→ */
217→export async function fetchExistingToolsForServer(
218→  surreal: Surreal,
219→  serverRecord: RecordId<"mcp_server", string>,
220→): Promise<ExistingToolRecord[]> {
221→  const results = await surreal.query<[ExistingToolRecord[]]>(
222→    `SELECT name, description, input_schema, output_schema, risk_level, status
223→     FROM mcp_tool
224→     WHERE source_server = $server;`,
225→    { server: serverRecord },
226→  );
227→  return results[0] ?? [];
228→}
229→
230→/**
231→ * Run full discovery: connect to MCP server, list tools, diff against
232→ * existing records, optionally apply changes.
233→ *
234→ * Returns a DiscoveryResult with per-tool sync details + summary counts.
235→ */
236→export async function discoverTools(
237→  deps: DiscoveryDeps,
238→  server: McpServerRecord,
239→  options: DiscoverToolsOptions,
240→): Promise<SyncApplyResult> {
241→  const serverRecord = server.id;
242→
243→  // 1. Resolve auth headers for the server, then connect
244→  const authHeaders = deps.toolEncryptionKey
