  1→/**
  2→ * SurrealDB queries for credential_provider and connected_account CRUD.
  3→ */
  4→import { RecordId, type Surreal } from "surrealdb";
  5→import type { CredentialProviderRecord, ConnectedAccountRecord } from "./types";
  6→
  7→/**
  8→ * Check if a provider with the given name already exists in the workspace.
  9→ */
 10→export async function providerNameExists(
 11→  surreal: Surreal,
 12→  workspaceRecord: RecordId<"workspace", string>,
 13→  name: string,
 14→): Promise<boolean> {
 15→  const results = await surreal.query<[Array<{ id: RecordId }>]>(
 16→    `SELECT id FROM credential_provider WHERE workspace = $ws AND name = $name LIMIT 1;`,
 17→    { ws: workspaceRecord, name },
 18→  );
 19→  return (results[0] ?? []).length > 0;
 20→}
 21→
 22→/**
 23→ * Find an existing credential_provider by discovery_source URL in a workspace.
 24→ * Used to deduplicate providers created via OAuth discovery.
 25→ */
 26→export async function findProviderByDiscoverySource(
 27→  surreal: Surreal,
 28→  workspaceRecord: RecordId<"workspace", string>,
 29→  discoverySource: string,
 30→): Promise<CredentialProviderRecord | undefined> {
 31→  const results = await surreal.query<[CredentialProviderRecord[]]>(
 32→    `SELECT * FROM credential_provider WHERE workspace = $ws AND discovery_source = $src LIMIT 1;`,
 33→    { ws: workspaceRecord, src: discoverySource },
 34→  );
 35→  return (results[0] ?? [])[0];
 36→}
 37→
 38→/**
 39→ * Create a credential_provider record.
 40→ */
 41→export async function createProvider(
 42→  surreal: Surreal,
 43→  workspaceRecord: RecordId<"workspace", string>,
 44→  content: Record<string, unknown>,
 45→): Promise<CredentialProviderRecord> {
 46→  const providerId = crypto.randomUUID();
 47→  const providerRecord = new RecordId("credential_provider", providerId);
 48→
 49→  const fullContent = {
 50→    ...content,
 51→    workspace: workspaceRecord,
 52→    created_at: new Date(),
 53→  };
 54→
 55→  await surreal.query(`CREATE $provider CONTENT $content;`, {
 56→    provider: providerRecord,
