223→/**
224→ * Count successful tool executions for today (UTC midnight to now).
225→ * Used for max_per_day enforcement on governs_tool edges.
226→ */
227→export async function countTodayToolExecutions(
228→  surreal: Surreal,
229→  toolName: string,
230→  workspaceId: string,
231→): Promise<number> {
232→  const workspaceRecord = new RecordId("workspace", workspaceId);
233→
234→  const results = await surreal.query<[Array<{ count: number }>]>(
235→    `SELECT count() AS count FROM trace
236→     WHERE type = 'tool_call'
237→       AND tool_name = $toolName
238→       AND workspace = $ws
239→       AND output.outcome = 'success'
240→       AND created_at >= time::floor(time::now(), 1d)
241→     GROUP ALL;`,
242→    { toolName, ws: workspaceRecord },
243→  );
244→
245→  return (results[0] ?? [])[0]?.count ?? 0;
246→}
