293→       basic_password_encrypted = NONE,
294→       bearer_token_encrypted = NONE,
295→       updated_at = time::now()
296→     WHERE identity = $identity AND workspace = $ws;`,
297→    { acct: accountRecord, identity: identityRecord, ws: workspaceRecord },
298→  );
299→  return (results[0] ?? [])[0];
300→}
