393→ * Returns undefined if the tool does not exist or does not belong to the workspace.
394→ */
395→export async function getToolDetail(
396→  surreal: Surreal,
397→  toolRecord: RecordId<"mcp_tool", string>,
398→  workspaceRecord: RecordId<"workspace", string>,
399→): Promise<
400→  | {
401→      tool: ToolDetailRow;
402→      grants: GrantDetailRow[];
403→      governancePolicies: GovernancePolicyDetailRow[];
404→    }
405→  | undefined
406→> {
407→  const results = await surreal.query<
408→    [ToolDetailRow[], GrantDetailRow[], GovernancePolicyDetailRow[]]
409→  >(
410→    `SELECT * FROM $tool WHERE workspace = $ws;
411→     SELECT in.id AS identity_id, in.name AS identity_name, max_calls_per_hour, granted_at FROM can_use WHERE out = $tool;
412→     SELECT in.title AS policy_title, in.status AS policy_status, conditions, max_per_call, max_per_day FROM governs_tool WHERE out = $tool;`,
413→    { tool: toolRecord, ws: workspaceRecord },
414→  );
415→
416→  const toolRows = results[0] ?? [];
417→  if (toolRows.length === 0) {
418→    return undefined;
419→  }
420→
421→  return {
422→    tool: toolRows[0],
423→    grants: results[1] ?? [],
424→    governancePolicies: results[2] ?? [],
425→  };
426→}
