527→ */
528→export async function createGovernanceEdge(
529→  surreal: Surreal,
530→  policyRecord: RecordId<"policy", string>,
531→  toolRecord: RecordId<"mcp_tool", string>,
532→  options?: {
533→    conditions?: string;
534→    maxPerCall?: number;
535→    maxPerDay?: number;
536→  },
537→): Promise<void> {
538→  const setClauses: string[] = [];
539→  const bindings: Record<string, unknown> = {
540→    policy: policyRecord,
541→    tool: toolRecord,
542→  };
543→
544→  if (options?.conditions !== undefined) {
545→    setClauses.push(`conditions = $conditions`);
546→    bindings.conditions = options.conditions;
547→  }
548→  if (options?.maxPerCall !== undefined) {
549→    setClauses.push(`max_per_call = $maxPerCall`);
550→    bindings.maxPerCall = options.maxPerCall;
551→  }
552→  if (options?.maxPerDay !== undefined) {
553→    setClauses.push(`max_per_day = $maxPerDay`);
554→    bindings.maxPerDay = options.maxPerDay;
555→  }
556→
557→  const setString = setClauses.length > 0 ? `SET ${setClauses.join(", ")}` : "";
558→
559→  await surreal.query(
