 58→
 59→const RISK_BADGES: Record<string, BadgeViewModel> = {
 60→  low: { label: "Low", variant: "outline", className: "text-green-600 border-green-300" },
 61→  medium: { label: "Medium", variant: "outline", className: "text-amber-600 border-amber-300" },
 62→  high: { label: "High", variant: "outline", className: "text-red-600 border-red-300" },
 63→  critical: { label: "Critical", variant: "destructive" },
 64→};
