 70→const STATUS_BADGES: Record<string, BadgeViewModel> = {
 71→  active: { label: "Active", variant: "default" },
 72→  disabled: { label: "Disabled", variant: "secondary" },
 73→};
 74→
 75→export function deriveStatusBadge(status: string): BadgeViewModel {
 76→  return STATUS_BADGES[status] ?? { label: status, variant: "outline" };
 77→}
 78→
 79→// ---------------------------------------------------------------------------
 80→// Description truncation
 81→// ---------------------------------------------------------------------------
 82→
 83→const MAX_DESCRIPTION_LENGTH = 100;
 84→
