  7→import { ToolTable, type ToolTableFilters } from "../components/tool-registry/ToolTable";
  8→import { McpServerSection, type AddMcpServerFormData } from "../components/tool-registry/McpServerSection";
  9→import type { CreateProviderFormData } from "../components/tool-registry/ProviderTable";
 10→import { useProviders } from "../hooks/use-providers";
 11→import { useAccounts } from "../hooks/use-accounts";
 12→import { useTools } from "../hooks/use-tools";
 13→import { useMcpServers } from "../hooks/use-mcp-servers";
