 15→
 16→// ---------------------------------------------------------------------------
 17→// Tab definitions
 18→// ---------------------------------------------------------------------------
 19→
 20→export type ToolRegistryTabId = "servers" | "tools" | "providers" | "accounts";
 21→
 22→export type ToolRegistryTab = {
 23→  id: ToolRegistryTabId;
 24→  label: string;
 25→};
 26→
 27→/** Primary tabs visible by default. */
 28→const PRIMARY_TABS: readonly ToolRegistryTab[] = [
 29→  { id: "servers", label: "Servers" },
 30→  { id: "tools", label: "Tools" },
 31→] as const;
 32→
 33→/** Advanced/debug tabs — collapsed behind a separator. */
 34→const ADVANCED_TABS: readonly ToolRegistryTab[] = [
 35→  { id: "providers", label: "Providers" },
 36→  { id: "accounts", label: "Accounts" },
 37→] as const;
 38→
 39→export const TOOL_REGISTRY_TABS: readonly ToolRegistryTab[] = [
 40→  ...PRIMARY_TABS,
 41→  ...ADVANCED_TABS,
 42→] as const;
 43→
 44→const VALID_TAB_IDS = new Set<string>(TOOL_REGISTRY_TABS.map((t) => t.id));
 45→const DEFAULT_TAB: ToolRegistryTabId = "servers";
 46→
 47→// ---------------------------------------------------------------------------
 48→// Pure view model
 49→// ---------------------------------------------------------------------------
 50→
 51→export type ToolRegistryPageInput = {
 52→  tabParam?: string;
 53→  toolsCount: number;
 54→  providersCount: number;
 55→  accountsCount: number;
 56→  mcpServersCount: number;
 57→};
 58→
 59→export type ToolRegistryViewModel = {
 60→  activeTab: ToolRegistryTabId;
 61→  showEmptyState: boolean;
 62→  tabLabels: Record<ToolRegistryTabId, string>;
 63→};
 64→
 65→function countForTab(
 66→  tabId: ToolRegistryTabId,
 67→  input: ToolRegistryPageInput,
 68→): number {
 69→  switch (tabId) {
 70→    case "servers":
 71→      return input.mcpServersCount;
 72→    case "tools":
 73→      return input.toolsCount;
 74→    case "providers":
 75→      return input.providersCount;
 76→    case "accounts":
 77→      return input.accountsCount;
 78→  }
 79→}
 80→
 81→function formatTabLabel(baseLabel: string, count: number): string {
 82→  return count > 0 ? `${baseLabel} (${count})` : baseLabel;
 83→}
 84→
 85→export function deriveToolRegistryViewModel(
 86→  input: ToolRegistryPageInput,
 87→): ToolRegistryViewModel {
 88→  const activeTab: ToolRegistryTabId =
 89→    input.tabParam && VALID_TAB_IDS.has(input.tabParam)
 90→      ? (input.tabParam as ToolRegistryTabId)
 91→      : DEFAULT_TAB;
 92→
 93→  const activeCount = countForTab(activeTab, input);
 94→  const showEmptyState = activeCount === 0;
 95→
 96→  const tabLabels = Object.fromEntries(
 97→    TOOL_REGISTRY_TABS.map((tab) => [
 98→      tab.id,
 99→      formatTabLabel(tab.label, countForTab(tab.id, input)),
100→    ]),
101→  ) as Record<ToolRegistryTabId, string>;
102→
103→  return {
104→    activeTab,
105→    showEmptyState,
106→    tabLabels,
107→  };
108→}
