114→export function ToolRegistryPage() {
115→  const search = useSearch({ strict: false }) as { tab?: string };
116→  const navigate = useNavigate();
117→  const workspaceId = useWorkspaceState((s) => s.workspaceId) ?? "default";
118→  const { tools, refresh: refreshTools } = useTools();
119→  const { providers, refresh: refreshProviders } = useProviders();
120→  const { mcpServers = [], refresh: refreshMcpServers } = useMcpServers();
121→
122→  // Lazy-load accounts only when the accounts tab is active — the endpoint
123→  // requires a Better Auth session and would 401 on every page load otherwise.
124→  const isAccountsTab = search.tab === "accounts";
125→  const { accounts, refresh: refreshAccounts } = useAccounts({ enabled: isAccountsTab });
126→
127→  // ---------------------------------------------------------------------------
128→  // MCP Server handlers
129→  // ---------------------------------------------------------------------------
130→
131→  const handleAddServer = useCallback(
132→    async (formData: AddMcpServerFormData): Promise<{ error?: string }> => {
133→      try {
134→        const payload: Record<string, unknown> = {
135→          name: formData.name,
136→          url: formData.url,
137→          transport: formData.transport,
138→          auth_mode: formData.auth_mode,
139→        };
140→        if (formData.auth_mode === "static_headers") {
141→          payload.static_headers = formData.static_headers;
142→        }
143→        if (formData.auth_mode === "provider" && formData.credentialProviderId) {
144→          payload.provider_id = formData.credentialProviderId;
145→        }
146→        const response = await fetch(
147→          `/api/workspaces/${encodeURIComponent(workspaceId)}/mcp-servers`,
148→          {
149→            method: "POST",
150→            headers: { "Content-Type": "application/json" },
151→            body: JSON.stringify(payload),
152→          },
153→        );
154→        if (!response.ok) {
155→          const text = await response.text();
156→          try {
157→            const body = JSON.parse(text) as { error?: string };
158→            return { error: (body.error ?? text) || "Failed to add server" };
159→          } catch {
160→            return { error: text || "Failed to add server" };
161→          }
162→        }
163→        const data = (await response.json()) as { authorization_url?: string };
164→
165→        // If the server supports OAuth, the backend auto-discovered and generated
166→        // an authorization URL — open it so the user can authorize immediately.
167→        if (data.authorization_url) {
168→          window.open(data.authorization_url, "_blank");
169→        }
170→
171→        refreshMcpServers();
172→        refreshProviders();
173→        return {};
174→      } catch {
175→        return { error: "Network error" };
176→      }
177→    },
178→    [workspaceId, refreshMcpServers, refreshProviders],
179→  );
180→
181→  const handleRemoveServer = useCallback(
182→    async (serverId: string) => {
183→      try {
184→        await fetch(
185→          `/api/workspaces/${encodeURIComponent(workspaceId)}/mcp-servers/${encodeURIComponent(serverId)}`,
186→          { method: "DELETE" },
187→        );
188→        refreshMcpServers();
189→      } catch {
190→        // silently fail
191→      }
192→    },
193→    [workspaceId, refreshMcpServers],
194→  );
195→
196→  const handleDiscoverTools = useCallback(
197→    async (serverId: string): Promise<{ error?: string }> => {
198→      try {
199→        const response = await fetch(
200→          `/api/workspaces/${encodeURIComponent(workspaceId)}/mcp-servers/${encodeURIComponent(serverId)}/discover`,
201→          { method: "POST" },
202→        );
203→        refreshMcpServers();
204→        refreshTools();
205→        if (!response.ok) {
206→          const body = await response.json().catch(() => ({})) as { error?: string };
207→          return { error: body.error ?? "Discovery failed" };
