    render(<ToolRegistryPage />);

    const toolsTab = screen.getByRole("tab", { name: /tools/i });
    await user.click(toolsTab);

    expect(mockNavigate).toHaveBeenCalledWith(
      expect.objectContaining({ search: { tab: "tools" } }),
