  1→/**
  2→ * MCP Client Module
  3→ *
  4→ * Provides functions to connect to upstream MCP servers, list tools,
  5→ * call tools, and disconnect. Supports SSE and Streamable HTTP transports.
  6→ *
  7→ * The McpClientFactory type is injectable via ServerDependencies so tests
  8→ * can substitute an InMemoryTransport-based factory.
  9→ *
 10→ * ADR-071: connect-per-request -- connections are established per proxy
 11→ * request, reused within request for multiple tool calls, and closed
 12→ * when the proxy request completes. No persistent connection pool.
 13→ */
 14→import { Client } from "@modelcontextprotocol/sdk/client/index.js";
 15→import { SSEClientTransport } from "@modelcontextprotocol/sdk/client/sse.js";
 16→import { StreamableHTTPClientTransport } from "@modelcontextprotocol/sdk/client/streamableHttp.js";
 17→import type { Transport } from "@modelcontextprotocol/sdk/shared/transport.js";
 18→import type {
 19→  ServerCapabilities,
 20→  Implementation as ServerInfo,
 21→} from "@modelcontextprotocol/sdk/types.js";
 22→import type { McpTransport } from "./types";
 23→
 24→// ---------------------------------------------------------------------------
 25→// Types
 26→// ---------------------------------------------------------------------------
 27→
 28→/** Result of Client.listTools() */
 29→export type ToolListResult = Awaited<ReturnType<Client["listTools"]>>;
 30→
 31→/** Result of Client.callTool() */
 32→export type CallToolResult = Awaited<ReturnType<Client["callTool"]>>;
 33→
 34→/**
 35→ * Result of a successful MCP server connection.
 36→ */
 37→export type McpConnectionResult = {
 38→  client: Client;
 39→  serverInfo: ServerInfo;
 40→  capabilities: ServerCapabilities;
 41→};
 42→
 43→/**
 44→ * Injectable factory for MCP client operations.
 45→ * Injected via ServerDependencies so tests can provide a mock implementation
 46→ * backed by InMemoryTransport.
 47→ */
 48→export type McpClientFactory = {
 49→  connect: (
 50→    url: string,
 51→    transport: McpTransport,
 52→    headers?: Record<string, string>,
