import { Link, useMatchRoute } from "@tanstack/react-router";
import type { ConversationSidebarItem, WorkspaceConversationSidebarResponse } from "../../../shared/contracts";
import { usePendingLearningCount } from "../../hooks/use-pending-learning-count";
import { Badge } from "../ui/badge";
import { Separator } from "../ui/separator";
import { Button } from "../ui/button";
import { cn } from "@/lib/utils";

type WorkspaceSidebarProps = {
  sidebar?: WorkspaceConversationSidebarResponse;
  activeConversationId?: string;
  isLoading: boolean;
  onNewConversation: () => void;
  onSelectConversation: (conversationId: string) => void;
};

export function WorkspaceSidebar({
  sidebar,
  activeConversationId,
  isLoading,
  onNewConversation,
  onSelectConversation,
}: WorkspaceSidebarProps) {
  const matchRoute = useMatchRoute();
  const isHome = matchRoute({ to: "/" });
  const isGraph = matchRoute({ to: "/graph" });
  const isLearnings = matchRoute({ to: "/learnings" });
  const isPolicies = matchRoute({ to: "/policies" });
  const isTools = matchRoute({ to: "/tools" });
  const { pendingCount } = usePendingLearningCount();

  function renderConversationItem(conv: ConversationSidebarItem, depth: number = 0) {
    return (
      <li key={conv.id}>
        <button
          type="button"
          className={cn(
            "flex w-full items-center gap-1 truncate rounded-md px-2 py-1.5 text-left text-xs text-foreground transition-colors hover:bg-hover",
            conv.id === activeConversationId && "bg-active text-accent",
            depth > 0 && "text-muted-foreground",
          )}
          style={depth > 0 ? { paddingLeft: `${8 + depth * 12}px` } : undefined}
          onClick={() => onSelectConversation(conv.id)}
        >
          {depth > 0 ? "\u21b3 " : ""}{conv.title}
        </button>
        {conv.branches && conv.branches.length > 0 ? (
          <ul className="flex flex-col">
            {conv.branches.map((branch) => renderConversationItem(branch, depth + 1))}
          </ul>
        ) : undefined}
      </li>
    );
  }

  const navItemClass = (active: boolean | object | undefined) =>
    cn(
      "flex items-center gap-2 rounded-md px-2 py-1.5 text-xs font-medium text-foreground transition-colors hover:bg-hover",
      active && "bg-active text-accent",
    );

  return (
    <aside className="flex w-[200px] shrink-0 flex-col gap-1 overflow-y-auto border-r border-border bg-sidebar p-2">
      {/* Navigation links */}
      <Link to="/" className={navItemClass(isHome)}>Feed</Link>
      <Link to="/graph" className={navItemClass(isGraph)}>Graph</Link>
      <Link to="/learnings" className={navItemClass(isLearnings)}>
        Learnings
        {pendingCount > 0 ? (
          <Badge variant="secondary" className="ml-auto h-4 min-w-4 px-1 text-[0.6rem]">{pendingCount}</Badge>
        ) : undefined}
      </Link>
      <Link to="/policies" className={navItemClass(isPolicies)}>Policies</Link>
      <Link to="/tools" className={navItemClass(isTools)}>Tool Registry</Link>

      <Separator className="my-1" />

      {/* Projects section */}
      <div className="flex flex-col gap-0.5">
        <span className="px-2 text-[0.65rem] font-semibold uppercase tracking-wider text-muted-foreground">Projects</span>
        {sidebar?.groups.map((group) => (
          <Link
            key={group.projectId}
            to="/"
            className={cn(
              "truncate rounded-md px-2 py-1 text-xs text-entity-project-fg transition-colors hover:bg-hover",
            )}
          >
            #{group.projectName}
          </Link>
        ))}
      </div>

      {/* Agents section */}
      <div className="flex flex-col gap-0.5">
        <span className="px-2 text-[0.65rem] font-semibold uppercase tracking-wider text-muted-foreground">Agents</span>
        <span className="px-2 py-1 text-xs text-entity-task-fg">@pm</span>
      </div>

      <Separator className="my-1" />

      {/* Chats section */}
      <div className="flex flex-1 flex-col gap-0.5 overflow-y-auto">
        <div className="flex items-center justify-between px-2">
          <span className="text-[0.65rem] font-semibold uppercase tracking-wider text-muted-foreground">Chats</span>
          <Button
            variant="ghost"
            size="icon-xs"
            onClick={onNewConversation}
            disabled={isLoading}
            title="New conversation"
          >
            +
          </Button>
        </div>
        {sidebar?.groups.map((group) =>
          group.conversations.length > 0 ? (
            <ul key={group.projectId} className="flex flex-col">
              {group.conversations.map((conv) => renderConversationItem(conv))}
            </ul>
          ) : undefined,
        )}
        {sidebar && sidebar.unlinked.length > 0 ? (
          <ul className="flex flex-col">
            {sidebar.unlinked.map((conv) => renderConversationItem(conv))}
          </ul>
        ) : undefined}
      </div>
    </aside>
  );
}

import { useCallback, useState } from "react";
import { useNavigate, useSearch } from "@tanstack/react-router";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "../components/ui/tabs";
import { ProviderTable } from "../components/tool-registry/ProviderTable";
import { CreateProviderDialog } from "../components/tool-registry/CreateProviderDialog";
import { AccountTable, type ProviderInfo } from "../components/tool-registry/AccountTable";
import { ToolTable, type ToolTableFilters } from "../components/tool-registry/ToolTable";
import { McpServerSection, type AddMcpServerFormData } from "../components/tool-registry/McpServerSection";
import type { CreateProviderFormData } from "../components/tool-registry/ProviderTable";
import { useProviders } from "../hooks/use-providers";
import { useAccounts } from "../hooks/use-accounts";
import { useTools } from "../hooks/use-tools";
import { useMcpServers } from "../hooks/use-mcp-servers";
import { useWorkspaceState } from "../stores/workspace-state";

// ---------------------------------------------------------------------------
// Tab definitions
// ---------------------------------------------------------------------------

export type ToolRegistryTabId = "servers" | "tools" | "providers" | "accounts";

export type ToolRegistryTab = {
  id: ToolRegistryTabId;
  label: string;
};

/** Primary tabs visible by default. */
const PRIMARY_TABS: readonly ToolRegistryTab[] = [
  { id: "servers", label: "Servers" },
  { id: "tools", label: "Tools" },
] as const;

/** Advanced/debug tabs — collapsed behind a separator. */
const ADVANCED_TABS: readonly ToolRegistryTab[] = [
  { id: "providers", label: "Providers" },
  { id: "accounts", label: "Accounts" },
] as const;

export const TOOL_REGISTRY_TABS: readonly ToolRegistryTab[] = [
  ...PRIMARY_TABS,
  ...ADVANCED_TABS,
] as const;

const VALID_TAB_IDS = new Set<string>(TOOL_REGISTRY_TABS.map((t) => t.id));
const DEFAULT_TAB: ToolRegistryTabId = "servers";

// ---------------------------------------------------------------------------
// Pure view model
// ---------------------------------------------------------------------------

export type ToolRegistryPageInput = {
  tabParam?: string;
  toolsCount: number;
  providersCount: number;
  accountsCount: number;
  mcpServersCount: number;
};

export type ToolRegistryViewModel = {
  activeTab: ToolRegistryTabId;
  showEmptyState: boolean;
  tabLabels: Record<ToolRegistryTabId, string>;
};

function countForTab(
  tabId: ToolRegistryTabId,
  input: ToolRegistryPageInput,
): number {
  switch (tabId) {
    case "servers":
      return input.mcpServersCount;
    case "tools":
      return input.toolsCount;
    case "providers":
      return input.providersCount;
    case "accounts":
      return input.accountsCount;
  }
}

function formatTabLabel(baseLabel: string, count: number): string {
  return count > 0 ? `${baseLabel} (${count})` : baseLabel;
}

export function deriveToolRegistryViewModel(
  input: ToolRegistryPageInput,
): ToolRegistryViewModel {
  const activeTab: ToolRegistryTabId =
    input.tabParam && VALID_TAB_IDS.has(input.tabParam)
      ? (input.tabParam as ToolRegistryTabId)
      : DEFAULT_TAB;

  const activeCount = countForTab(activeTab, input);
  const showEmptyState = activeCount === 0;

  const tabLabels = Object.fromEntries(
    TOOL_REGISTRY_TABS.map((tab) => [
      tab.id,
      formatTabLabel(tab.label, countForTab(tab.id, input)),
    ]),
  ) as Record<ToolRegistryTabId, string>;

  return {
    activeTab,
    showEmptyState,
    tabLabels,
  };
}

// ---------------------------------------------------------------------------
// React component
// ---------------------------------------------------------------------------

export function ToolRegistryPage() {
  const search = useSearch({ strict: false }) as { tab?: string };
  const navigate = useNavigate();
  const workspaceId = useWorkspaceState((s) => s.workspaceId) ?? "default";
  const { tools, refresh: refreshTools } = useTools();
  const { providers, refresh: refreshProviders } = useProviders();
  const { mcpServers = [], refresh: refreshMcpServers } = useMcpServers();

  // Lazy-load accounts only when the accounts tab is active — the endpoint
  // requires a Better Auth session and would 401 on every page load otherwise.
  const isAccountsTab = search.tab === "accounts";
  const { accounts, refresh: refreshAccounts } = useAccounts({ enabled: isAccountsTab });

  // ---------------------------------------------------------------------------
  // MCP Server handlers
  // ---------------------------------------------------------------------------

  const handleAddServer = useCallback(
    async (formData: AddMcpServerFormData): Promise<{ error?: string }> => {
      try {
        const payload: Record<string, unknown> = {
          name: formData.name,
          url: formData.url,
          transport: formData.transport,
          auth_mode: formData.auth_mode,
        };
        if (formData.auth_mode === "static_headers") {
          payload.static_headers = formData.static_headers;
        }
        if (formData.auth_mode === "provider" && formData.credentialProviderId) {
          payload.provider_id = formData.credentialProviderId;
        }
        const response = await fetch(
          `/api/workspaces/${encodeURIComponent(workspaceId)}/mcp-servers`,
          {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(payload),
          },
        );
        if (!response.ok) {
          const text = await response.text();
          try {
            const body = JSON.parse(text) as { error?: string };
            return { error: (body.error ?? text) || "Failed to add server" };
          } catch {
            return { error: text || "Failed to add server" };
          }
        }
        const data = (await response.json()) as { authorization_url?: string };

        // If the server supports OAuth, the backend auto-discovered and generated
        // an authorization URL — open it so the user can authorize immediately.
        if (data.authorization_url) {
          window.open(data.authorization_url, "_blank");
        }

        refreshMcpServers();
        refreshProviders();
        return {};
      } catch {
        return { error: "Network error" };
      }
    },
    [workspaceId, refreshMcpServers, refreshProviders],
  );

  const handleRemoveServer = useCallback(
    async (serverId: string) => {
      try {
        await fetch(
          `/api/workspaces/${encodeURIComponent(workspaceId)}/mcp-servers/${encodeURIComponent(serverId)}`,
          { method: "DELETE" },
        );
        refreshMcpServers();
      } catch {
        // silently fail
      }
    },
    [workspaceId, refreshMcpServers],
  );

  const handleDiscoverTools = useCallback(
    async (serverId: string): Promise<{ error?: string }> => {
      try {
        const response = await fetch(
          `/api/workspaces/${encodeURIComponent(workspaceId)}/mcp-servers/${encodeURIComponent(serverId)}/discover`,
          { method: "POST" },
        );
        refreshMcpServers();
        refreshTools();
        if (!response.ok) {
          const body = await response.json().catch(() => ({})) as { error?: string };
          return { error: body.error ?? "Discovery failed" };
        }
        return {};
      } catch {
        return { error: "Network error" };
      }
    },
    [workspaceId, refreshMcpServers, refreshTools],
  );

  const handleSyncTools = useCallback(
    async (serverId: string): Promise<{ error?: string }> => {
      try {
        const response = await fetch(
          `/api/workspaces/${encodeURIComponent(workspaceId)}/mcp-servers/${encodeURIComponent(serverId)}/sync`,
          { method: "POST" },
        );
        refreshMcpServers();
        refreshTools();
        if (!response.ok) {
          const body = await response.json().catch(() => ({})) as { error?: string };
          return { error: body.error ?? "Sync failed" };
        }
        return {};
      } catch {
        return { error: "Network error" };
      }
    },
    [workspaceId, refreshMcpServers, refreshTools],
  );

  const handleAuthorize = useCallback(
    async (serverId: string) => {
      try {
        const response = await fetch(
          `/api/workspaces/${encodeURIComponent(workspaceId)}/mcp-servers/${encodeURIComponent(serverId)}/authorize`,
          { method: "POST" },
        );
        if (!response.ok) return;
        const data = (await response.json()) as { authorization_url?: string };
        if (data.authorization_url) {
          window.open(data.authorization_url, "_blank");
        }
      } catch {
        // silently fail
      }
    },
    [workspaceId],
  );

  const handleRevokeGrant = useCallback(
    async (toolId: string, identityId: string) => {
      try {
        await fetch(
          `/api/workspaces/default/tools/${encodeURIComponent(toolId)}/grants/${encodeURIComponent(identityId)}`,
          { method: "DELETE" },
        );
        refreshTools();
      } catch {
        // silently fail for now
      }
    },
    [refreshTools],
  );

  const handleCreateProvider = useCallback(
    async (formData: CreateProviderFormData): Promise<{ error?: string }> => {
      try {
        const response = await fetch(`/api/workspaces/default/providers`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(formData),
        });
        if (!response.ok) {
          const body = await response.text();
          return { error: body || "Failed to create provider" };
        }
        refreshProviders();
        return {};
      } catch {
        return { error: "Network error" };
      }
    },
    [refreshProviders],
  );

  const handleDeleteProvider = useCallback(
    async (providerId: string) => {
      try {
        await fetch(`/api/workspaces/default/providers/${providerId}`, {
          method: "DELETE",
        });
        refreshProviders();
      } catch {
        // silently fail for now
      }
    },
    [refreshProviders],
  );

  const handleRevokeAccount = useCallback(
    async (accountId: string) => {
      try {
        await fetch(`/api/workspaces/default/accounts/${accountId}/revoke`, {
          method: "POST",
        });
        refreshAccounts();
      } catch {
        // silently fail for now
      }
    },
    [refreshAccounts],
  );

  const handleReconnectAccount = useCallback(
    (_accountId: string, _authMethod: string) => {
      // TODO: open connect dialog for reconnection
    },
    [],
  );

  const [toolFilters, setToolFilters] = useState<ToolTableFilters>({
    searchText: "",
  });

  const handleToolSearchChange = useCallback((searchText: string) => {
    setToolFilters((prev) => ({ ...prev, searchText }));
  }, []);

  const handleToolStatusFilterChange = useCallback((status?: string) => {
    setToolFilters((prev) => ({ ...prev, status }));
  }, []);

  const handleToolRiskFilterChange = useCallback((riskLevel?: string) => {
    setToolFilters((prev) => ({ ...prev, riskLevel }));
  }, []);

  const providerInfoList: ProviderInfo[] = providers.map((p) => ({
    id: p.id,
    displayName: p.display_name,
    authMethod: p.auth_method,
  }));

  const vm = deriveToolRegistryViewModel({
    tabParam: search.tab,
    toolsCount: tools.length,
    providersCount: providers.length,
    accountsCount: accounts.length,
    mcpServersCount: mcpServers.length,
  });

  const handleTabChange = useCallback(
    (value: string) => {
      void navigate({
        to: "/tools",
        search: { tab: value },
      } as never);
    },
    [navigate],
  );

  return (
    <section className="mx-auto flex max-w-5xl flex-col gap-4 p-6">
      <div className="flex items-center justify-between">
        <h1 className="text-lg font-semibold text-foreground">Tool Registry</h1>
      </div>
      <Tabs value={vm.activeTab} onValueChange={handleTabChange}>
        <TabsList variant="line">
          {PRIMARY_TABS.map((tab) => (
            <TabsTrigger key={tab.id} value={tab.id}>
              {vm.tabLabels[tab.id]}
            </TabsTrigger>
          ))}
          <span className="mx-2 h-4 w-px bg-border" aria-hidden="true" />
          {ADVANCED_TABS.map((tab) => (
            <TabsTrigger key={tab.id} value={tab.id} className="text-muted-foreground/60">
              {vm.tabLabels[tab.id]}
            </TabsTrigger>
          ))}
        </TabsList>
        <TabsContent value="servers">
          <div className="py-2">
            <McpServerSection
              servers={mcpServers}
              providers={providers}
              onAddServer={handleAddServer}
              onRemoveServer={handleRemoveServer}
              onDiscover={handleDiscoverTools}
              onSync={handleSyncTools}
              onAuthorize={handleAuthorize}
            />
          </div>
        </TabsContent>
        <TabsContent value="tools">
          {vm.showEmptyState && vm.activeTab === "tools" ? (
            <EmptyState message="No tools discovered yet." />
          ) : (
            <div className="flex flex-col gap-3 py-2">
              <div className="flex items-center gap-2">
                <input
                  type="text"
                  placeholder="Search tools..."
                  value={toolFilters.searchText}
                  onChange={(e) => handleToolSearchChange(e.target.value)}
                  className="h-8 rounded-md border px-3 text-sm"
                />
                <select
                  value={toolFilters.status ?? ""}
                  onChange={(e) =>
                    handleToolStatusFilterChange(e.target.value || undefined)
                  }
                  className="h-8 rounded-md border px-2 text-sm"
                >
                  <option value="">All statuses</option>
                  <option value="active">Active</option>
                  <option value="disabled">Disabled</option>
                </select>
                <select
                  value={toolFilters.riskLevel ?? ""}
                  onChange={(e) =>
                    handleToolRiskFilterChange(e.target.value || undefined)
                  }
                  className="h-8 rounded-md border px-2 text-sm"
                >
                  <option value="">All risk levels</option>
                  <option value="low">Low</option>
                  <option value="medium">Medium</option>
                  <option value="high">High</option>
                  <option value="critical">Critical</option>
                </select>
              </div>
              <ToolTable
                tools={tools}
                filters={toolFilters}
                actions={{
                  onGrantAccess: (_toolId) => {
                    // TODO: open CreateGrantDialog
                  },
                  onRevokeGrant: handleRevokeGrant,
                }}
              />
            </div>
          )}
        </TabsContent>
        <TabsContent value="providers">
          {providers.length === 0 ? (
            <EmptyState
              message="No credential providers configured."
              action={<CreateProviderDialog onSubmit={handleCreateProvider} />}
            />
          ) : (
            <>
              <div className="flex justify-end py-2">
                <CreateProviderDialog onSubmit={handleCreateProvider} />
              </div>
              <ProviderTable providers={providers} onDelete={handleDeleteProvider} />
            </>
          )}
        </TabsContent>
        <TabsContent value="accounts">
          {vm.showEmptyState && vm.activeTab === "accounts" ? (
            <EmptyState message="No accounts connected." />
          ) : (
            <AccountTable
              accounts={accounts}
              providers={providerInfoList}
              onRevoke={handleRevokeAccount}
              onReconnect={handleReconnectAccount}
            />
          )}
        </TabsContent>
      </Tabs>
    </section>
  );
}

// ---------------------------------------------------------------------------
// Empty state component
// ---------------------------------------------------------------------------

function EmptyState({ message, action }: { message: string; action?: React.ReactNode }) {
  return (
    <div className="flex flex-col items-center gap-3 py-12 text-center">
      <p className="text-sm text-muted-foreground">{message}</p>
      {action}
    </div>
  );
}

/**
 * MCP Tool Discovery Service
 *
 * Pure functions for diffing remote MCP server tools against local records,
 * inferring risk levels from MCP annotations, and filtering by selection.
 *
 * Effectful wrappers handle MCP client connections and DB persistence.
 *
 * Pure core (unit-testable):
 *   - inferRiskLevel(annotations) -> ToolRiskLevel
 *   - computeSyncActions(remoteTools, existingTools) -> ToolSyncDetail[]
 *   - filterBySelection(tools, selectedTools?) -> ToolSyncDetail[]
 *
 * Effectful boundary (acceptance-testable):
 *   - discoverTools(deps, server, options) -> DiscoveryResult
 *   - applySyncActions(deps, server, syncDetails) -> SyncApplyResult
 */
import { RecordId, type Surreal } from "surrealdb";
import type { McpClientFactory, ToolListResult } from "./mcp-client";
import type {
  ToolRiskLevel,
  ToolSyncAction,
  ToolSyncDetail,
  McpServerRecord,
  McpTransport,
} from "./types";
import { resolveAuthForMcpServer } from "../proxy/credential-resolver";

// ---------------------------------------------------------------------------
// Public types for pure functions
// ---------------------------------------------------------------------------

/**
 * A tool as reported by the remote MCP server (from client.listTools()).
 */
export type RemoteTool = {
  name: string;
  description: string;
  inputSchema: Record<string, unknown>;
  outputSchema?: Record<string, unknown>;
  annotations?: Record<string, unknown>;
};

/**
 * Minimal shape of an existing local mcp_tool record needed for diffing.
 */
export type ExistingToolRecord = {
  name: string;
  description: string;
  input_schema: Record<string, unknown>;
  output_schema?: Record<string, unknown>;
  risk_level: string;
  status: string;
};

/**
 * Result of applying sync actions to the database.
 */
export type SyncApplyResult = {
  created: number;
  updated: number;
  disabled: number;
  unchanged: number;
  tools: ToolSyncDetail[];
};

// ---------------------------------------------------------------------------
// Pure functions
// ---------------------------------------------------------------------------

/**
 * Infer risk level from MCP tool annotations.
 *
 * Priority:
 *   1. destructiveHint === true  -> "high"
 *   2. readOnlyHint === true     -> "low"
 *   3. idempotentHint === true   -> "low"
 *   4. default                   -> "medium"
 */
export function inferRiskLevel(
  annotations: Record<string, unknown> | undefined,
): ToolRiskLevel {
  if (!annotations) return "medium";

  if (annotations.destructiveHint === true) return "high";
  if (annotations.readOnlyHint === true) return "low";
  if (annotations.idempotentHint === true) return "low";

  return "medium";
}

/**
 * Compute sync actions by diffing remote tools against existing local records.
 *
 * For each remote tool:
 *   - Not in local           -> action: "create"
 *   - In local, schema/desc differs -> action: "update"
 *   - In local, identical    -> action: "unchanged"
 *
 * For each local tool NOT in remote (and still active):
 *   -> action: "disable"
 */
export function computeSyncActions(
  remoteTools: RemoteTool[],
  existingTools: ExistingToolRecord[],
): ToolSyncDetail[] {
  const existingByName = new Map(
    existingTools.map((tool) => [tool.name, tool]),
  );
  const remoteNames = new Set(remoteTools.map((tool) => tool.name));
  const result: ToolSyncDetail[] = [];

  // Process remote tools
  for (const remote of remoteTools) {
    const existing = existingByName.get(remote.name);
    const riskLevel = inferRiskLevel(remote.annotations);

    if (!existing) {
      result.push({
        name: remote.name,
        description: remote.description,
        input_schema: remote.inputSchema,
        output_schema: remote.outputSchema,
        action: "create",
        risk_level: riskLevel,
      });
      continue;
    }

    const descriptionChanged = remote.description !== existing.description;
    const inputSchemaChanged =
      JSON.stringify(remote.inputSchema) !==
      JSON.stringify(existing.input_schema);
    const outputSchemaChanged =
      JSON.stringify(remote.outputSchema) !==
      JSON.stringify(existing.output_schema);

    const action: ToolSyncAction =
      descriptionChanged || inputSchemaChanged || outputSchemaChanged
        ? "update"
        : "unchanged";

    result.push({
      name: remote.name,
      description: remote.description,
      input_schema: remote.inputSchema,
      output_schema: remote.outputSchema,
      action,
      risk_level: riskLevel,
    });
  }

  // Process local-only tools (candidates for disable)
  for (const existing of existingTools) {
    if (!remoteNames.has(existing.name) && existing.status !== "disabled") {
      result.push({
        name: existing.name,
        description: existing.description,
        input_schema: existing.input_schema,
        output_schema: existing.output_schema,
        action: "disable",
        risk_level: existing.risk_level as ToolRiskLevel,
      });
    }
  }

  return result;
}

/**
 * Filter sync details to only include tools in the selection list.
 * If no selection provided (undefined or empty array), returns all tools.
 */
export function filterBySelection(
  tools: ToolSyncDetail[],
  selectedTools: string[] | undefined,
): ToolSyncDetail[] {
  if (!selectedTools || selectedTools.length === 0) return tools;

  const selectedSet = new Set(selectedTools);
  return tools.filter((tool) => selectedSet.has(tool.name));
}

// ---------------------------------------------------------------------------
// Effectful functions (DB + MCP client)
// ---------------------------------------------------------------------------

/** Dependencies for the discovery service. */
export type DiscoveryDeps = {
  surreal: Surreal;
  mcpClientFactory: McpClientFactory;
  toolEncryptionKey?: string;
};

/** Options for the discoverTools function. */
export type DiscoverToolsOptions = {
  dryRun: boolean;
  selectedTools?: string[];
};

/**
 * Convert MCP SDK tool list result to our RemoteTool shape.
 */
export function toRemoteTools(toolListResult: ToolListResult): RemoteTool[] {
  return toolListResult.tools.map((tool) => ({
    name: tool.name,
    description: tool.description ?? "",
    inputSchema: (tool.inputSchema ?? {}) as Record<string, unknown>,
    outputSchema: tool.outputSchema as Record<string, unknown> | undefined,
    annotations: tool.annotations as Record<string, unknown> | undefined,
  }));
}

/**
 * Fetch existing mcp_tool records for a server from SurrealDB.
 */
export async function fetchExistingToolsForServer(
  surreal: Surreal,
  serverRecord: RecordId<"mcp_server", string>,
): Promise<ExistingToolRecord[]> {
  const results = await surreal.query<[ExistingToolRecord[]]>(
    `SELECT name, description, input_schema, output_schema, risk_level, status
     FROM mcp_tool
     WHERE source_server = $server;`,
    { server: serverRecord },
  );
  return results[0] ?? [];
}

/**
 * Run full discovery: connect to MCP server, list tools, diff against
 * existing records, optionally apply changes.
 *
 * Returns a DiscoveryResult with per-tool sync details + summary counts.
 */
export async function discoverTools(
  deps: DiscoveryDeps,
  server: McpServerRecord,
  options: DiscoverToolsOptions,
): Promise<SyncApplyResult> {
  const serverRecord = server.id;

  // 1. Resolve auth headers for the server, then connect
  const authHeaders = deps.toolEncryptionKey
    ? await resolveAuthForMcpServer(server, deps.toolEncryptionKey, {
        surreal: deps.surreal,
        toolEncryptionKey: deps.toolEncryptionKey,
      })
    : {};

  const connection = await deps.mcpClientFactory.connect(
    server.url,
    server.transport as McpTransport,
    Object.keys(authHeaders).length > 0 ? authHeaders : undefined,
  );

  let toolListResult: ToolListResult;
  try {
    toolListResult = await deps.mcpClientFactory.fetchToolList(
      connection.client,
    );
  } finally {
    await deps.mcpClientFactory.disconnect(connection.client).catch(() => {});
  }

  // 2. Convert to RemoteTool shape
  const remoteTools = toRemoteTools(toolListResult);

  // 3. Fetch existing local tools for this server
  const existingTools = await fetchExistingToolsForServer(
    deps.surreal,
    serverRecord,
  );

  // 4. Compute sync actions
  let syncDetails = computeSyncActions(remoteTools, existingTools);

  // 5. Apply selection filter
  syncDetails = filterBySelection(syncDetails, options.selectedTools);

  // 6. Count actions
  const counts = countActions(syncDetails);

  // 7. If not dry-run, apply changes to DB
  if (!options.dryRun) {
    await applySyncActions(deps.surreal, server, syncDetails);
  }

  return {
    ...counts,
    tools: syncDetails,
  };
}

/**
 * Count actions in a list of sync details.
 */
function countActions(tools: ToolSyncDetail[]): {
  created: number;
  updated: number;
  disabled: number;
  unchanged: number;
} {
  let created = 0;
  let updated = 0;
  let disabled = 0;
  let unchanged = 0;

  for (const tool of tools) {
    switch (tool.action) {
      case "create":
        created++;
        break;
      case "update":
        updated++;
        break;
      case "disable":
        disabled++;
        break;
      case "unchanged":
        unchanged++;
        break;
    }
  }

  return { created, updated, disabled, unchanged };
}

/**
 * Apply sync actions to SurrealDB: create/update/disable tools,
 * update server metadata.
 */
async function applySyncActions(
  surreal: Surreal,
  server: McpServerRecord,
  syncDetails: ToolSyncDetail[],
): Promise<void> {
  const serverRecord = server.id;
  const workspaceRecord = server.workspace;

  for (const tool of syncDetails) {
    switch (tool.action) {
      case "create": {
        const toolId = `tool-${crypto.randomUUID()}`;
        const toolRecord = new RecordId("mcp_tool", toolId);
        await surreal.query(`CREATE $tool CONTENT $content;`, {
          tool: toolRecord,
          content: {
            name: tool.name,
            description: tool.description,
            input_schema: tool.input_schema,
            output_schema: tool.output_schema,
            risk_level: tool.risk_level,
            toolkit: deriveToolkit(tool.name),
            status: "active",
            workspace: workspaceRecord,
            source_server: serverRecord,
            created_at: new Date(),
          },
        });
        break;
      }
      case "update": {
        await surreal.query(
          `UPDATE mcp_tool SET
             description = $description,
             input_schema = $inputSchema,
             output_schema = $outputSchema,
             risk_level = $riskLevel
           WHERE name = $name AND source_server = $server;`,
          {
            description: tool.description,
            inputSchema: tool.input_schema,
            outputSchema: tool.output_schema,
            riskLevel: tool.risk_level,
            name: tool.name,
            server: serverRecord,
          },
        );
        break;
      }
      case "disable": {
        await surreal.query(
          `UPDATE mcp_tool SET status = "disabled"
           WHERE name = $name AND source_server = $server;`,
          { name: tool.name, server: serverRecord },
        );
        break;
      }
      // "unchanged" -> no DB write needed
    }
  }

  // Update server metadata
  const activeToolCount = syncDetails.filter(
    (t) => t.action !== "disable",
  ).length;

  await surreal.query(
    `UPDATE $server SET
       last_discovery = time::now(),
       tool_count = $toolCount;`,
    { server: serverRecord, toolCount: activeToolCount },
  );
}

/**
 * Derive toolkit name from a tool name.
 * Convention: first segment before the dot, or the full name if no dot.
 */
function deriveToolkit(toolName: string): string {
  const dotIndex = toolName.indexOf(".");
  return dotIndex > 0 ? toolName.substring(0, dotIndex) : toolName;
}

